import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogClose } from "@/components/ui/dialog";
import { Share2, TrendingUp, TrendingDown, BarChart3, ExternalLink, Copy, Lock, X } from "lucide-react";
import { formatTimeAgo, getSentimentColor, getTypeColor } from "@/lib/utils";
import { getContextualImage } from "@/lib/imageUtils";
import type { Article } from "@shared/schema";
import { useState } from "react";
import { useToast } from "@/hooks/use-toast";
import { useLocation } from "wouter";
import { useAuth } from "@/hooks/useAuth";
import DirectLogin from "@/components/direct-login";
import ImageLightbox from "@/components/image-lightbox";

interface NewsCardProps {
  article: Article;
  onClick: () => void;
  onShare: (e: React.MouseEvent) => void;
  isExpanded?: boolean;
  onToggleExpanded?: () => void;
}

export default function NewsCard({ article, onClick, onShare }: NewsCardProps) {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);
  const [isLightboxOpen, setIsLightboxOpen] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [, setLocation] = useLocation();

  const sentimentColor = getSentimentColor(article.sentiment);
  const typeColor = getTypeColor(article.type || 'AI News');
  const { toast } = useToast();
  const { isAuthenticated, isLoading: authLoading } = useAuth();

  const handleCopyLink = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const articleLink = `${window.location.origin}/article/${article.id}`;
    try {
      await navigator.clipboard.writeText(articleLink);
      toast({
        title: "Link copied!",
        description: "Article link copied to clipboard",
      });
    } catch (err) {
      toast({
        title: "Copy failed",
        description: "Please copy the link manually",
        variant: "destructive",
      });
    }
  };

  const handleOpenArticle = (e: React.MouseEvent) => {
    e.stopPropagation();
    window.open(`/article/${article.id}`, '_blank');
  };

  const handleShare = (e: React.MouseEvent) => {
    e.stopPropagation();
    onShare(e);
  };

  const getSentimentIcon = () => {
    switch ((article.sentiment || 'neutral').toLowerCase()) {
      case 'positive':
        return <TrendingUp className="text-success h-3 w-3" />;
      case 'negative':
        return <TrendingDown className="text-danger h-3 w-3" />;
      default:
        return <BarChart3 className="text-primary h-3 w-3" />;
    }
  };

  const getSentimentBorderColor = () => {
    switch ((article.sentiment || 'neutral').toLowerCase()) {
      case 'positive':
        return 'border-l-green-500';
      case 'negative':
        return 'border-l-red-500';
      default:
        return 'border-l-primary';
    }
  };

  // Function to determine if content needs truncation 
  const shouldShowViewMore = () => {
    return article.content.length > 250;
  };

  // Function to get truncated content for preview
  const getTruncatedContent = (content: string) => {
    if (content.length <= 250) return content;

    const truncated = content.substring(0, 250);
    const lastSpaceIndex = truncated.lastIndexOf(' ');

    return lastSpaceIndex > 200 ? truncated.substring(0, lastSpaceIndex) : truncated;
  };

  const formatNewsContent = (content: string) => {
    return content
      .split('\n')
      .filter(line => line.trim() !== '')
      .map(line => {
        if (line.includes(':') || line.includes('-') || (line.length < 50 && line.trim().endsWith('.'))) {
          return `**${line.trim()}**`;
        }
        return line.trim();
      })
      .join('\n\n');
  };

  const handleViewMore = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
  };

  return (
    <>
      <div 
        className={`h-full w-full snap-start flex flex-col bg-white dark:bg-gray-900 relative overflow-hidden border-l-4 ${
          getSentimentBorderColor()
        } hover:shadow-lg transition-shadow duration-200`}
        onClick={onClick}
      >
        {/* Article Content Container - Inshorts Style */}
        <div className="flex flex-col h-full">
          {/* Special layout for locked StocksShorts Special articles */}
          {article.type === 'StocksShorts Special' && !isAuthenticated && !authLoading ? (
            <>
              {/* Login Section (Top) */}
              <div className="p-4 bg-gradient-to-b from-blue-50 to-white dark:from-blue-950 dark:to-gray-900 border-b border-blue-200 dark:border-blue-800">
                <div className="text-center space-y-4">
                  <Lock className="h-8 w-8 text-blue-600 mx-auto" />
                  <div>
                    <h3 className="font-bold text-lg mb-2 text-gray-900 dark:text-gray-100">{article.title}</h3>
                    <p className="text-sm text-blue-700 dark:text-blue-400 mb-2 font-medium">
                      🔒 LOGIN REQUIRED TO READ
                    </p>
                    <p className="text-xs text-gray-600 dark:text-gray-400 mb-4">
                      StocksShorts Special articles require authentication
                    </p>
                  </div>
                  <DirectLogin />
                </div>
              </div>

              {/* Image Section (Bottom - Blurred for locked content) */}
              <div className="w-full h-48 relative bg-gray-100 dark:bg-gray-800 overflow-hidden">
                <img
                  src={imageError ? getContextualImage(article) : (article.imageUrl || getContextualImage(article))}
                  alt={article.title}
                  className="w-full h-full object-contain filter blur-sm opacity-50"
                  onLoad={() => setImageLoaded(true)}
                  onError={(e) => {
                    setImageError(true);
                    e.currentTarget.src = getContextualImage(article);
                  }}
                />
                {/* Overlay to indicate locked content */}
                <div className="absolute inset-0 bg-black/20 flex items-center justify-center">
                  <div className="bg-white/90 dark:bg-gray-900/90 px-4 py-2 rounded-lg backdrop-blur-sm">
                    <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                      Preview - Login to view full content
                    </p>
                  </div>
                </div>
              </div>
            </>
          ) : (
            <>
              {/* Normal layout for other articles */}
              {/* Image Section (Top - Full Width) */}
              <div className="w-full h-64 relative bg-gray-100 dark:bg-gray-800">
                <img
                  src={imageError ? getContextualImage(article) : (article.imageUrl || getContextualImage(article))}
                  alt={article.title}
                  className="w-full h-full object-contain cursor-pointer"
                  onLoad={() => setImageLoaded(true)}
                  onError={(e) => {
                    setImageError(true);
                    e.currentTarget.src = getContextualImage(article);
                  }}
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsLightboxOpen(true);
                  }}
                />
              </div>

              {/* Content Section (Bottom - Full Width) */}
              <div className="flex-1 p-4 flex flex-col justify-between">
                <div className="h-full flex flex-col">
                  <div className="flex-1">
                    <h3 className="font-bold text-lg mb-2 line-clamp-2">{article.title}</h3>
                    {shouldShowViewMore() ? (
                      <div className="whitespace-pre-wrap text-gray-700 dark:text-gray-300 leading-relaxed">
                        {getTruncatedContent(article.content)}...{' '}
                        <button
                          onClick={handleViewMore}
                          className="text-blue-600 dark:text-blue-400 hover:text-blue-800 dark:hover:text-blue-300 text-sm font-medium underline"
                        >
                          View More
                        </button>
                      </div>
                    ) : (
                      <div className="whitespace-pre-wrap text-gray-700 dark:text-gray-300 leading-relaxed">
                        {article.content}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </>
          )}
        </div>

        {/* Source and time - positioned at bottom */}
          <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-white/95 dark:from-gray-900/95 via-white/80 dark:via-gray-900/80 to-transparent p-3">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3 text-xs text-gray-600 dark:text-gray-400">
                <span className="flex items-center space-x-1">
                  {getSentimentIcon()}
                  <span className="capitalize font-medium">{article.sentiment}</span>
                </span>
                <span className="text-gray-500">•</span>
                <span className="font-medium">{article.source}</span>
                <span className="text-gray-500">•</span>
                <span>{formatTimeAgo((article.time || new Date('2025-07-05T00:01:00Z')) as Date)}</span>
              </div>

              {/* Action buttons */}
              <div className="flex items-center space-x-2">
                <button
                  onClick={handleCopyLink}
                  className="p-1.5 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                  title="Copy link"
                >
                  <Copy className="h-3.5 w-3.5 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" />
                </button>

                <button
                  onClick={handleOpenArticle}
                  className="p-1.5 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                  title="Open article"
                >
                  <ExternalLink className="h-3.5 w-3.5 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" />
                </button>

                <button
                  onClick={handleShare}
                  className="p-1.5 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                  title="Share article"
                >
                  <Share2 className="h-3.5 w-3.5 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" />
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Image Lightbox */}
        <ImageLightbox
          src={imageError ? getContextualImage(article) : (article.imageUrl || getContextualImage(article))}
          alt={article.title}
          isOpen={isLightboxOpen}
          onClose={() => setIsLightboxOpen(false)}
        />
      </div>

      {/* Full Article Modal - RESTORED ORIGINAL DESIGN */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="text-lg font-bold pr-8">
              {article.title}
            </DialogTitle>
            <DialogClose asChild>
              <Button
                variant="ghost"
                className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-accent data-[state=open]:text-muted-foreground"
                onClick={handleCloseModal}
              >
                <X className="h-4 w-4" />
              </Button>
            </DialogClose>
          </DialogHeader>

          <div className="space-y-4">
            {/* Article Image in Modal */}
            {(article.imageUrl || getContextualImage(article)) && (
              <div className="relative w-full h-80 rounded-lg overflow-hidden flex items-center justify-center bg-gray-50 dark:bg-gray-800">
                <img
                  src={imageError ? getContextualImage(article) : (article.imageUrl || getContextualImage(article))}
                  alt={article.title}
                  className="max-w-full max-h-full object-contain"
                  onLoad={() => setImageLoaded(true)}
                  onError={() => setImageError(true)}
                />
              </div>
            )}

            {/* Article Content in Modal */}
            <div className="prose prose-sm dark:prose-invert max-w-none">
              <div className="whitespace-pre-wrap text-gray-700 dark:text-gray-300 leading-relaxed">
                {formatNewsContent(article.content)}
              </div>
            </div>

            {/* Meta Information */}
            <div className="flex items-center justify-between pt-4 border-t border-gray-200 dark:border-gray-700">
              <div className="flex items-center space-x-4 text-sm text-gray-500 dark:text-gray-400">
                <span className="flex items-center space-x-1">
                  {getSentimentIcon()}
                  <span className="capitalize">{article.sentiment}</span>
                </span>
                <span>{article.source}</span>
                <span>{formatTimeAgo((article.time || new Date('2025-07-05T00:01:00Z')) as Date)}</span>
              </div>

              {/* Share Button in Modal */}
              <Button
                variant="outline"
                size="sm"
                onClick={handleShare}
                className="ml-4"
              >
                <Share2 className="h-4 w-4 mr-2" />
                Share
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { useLocation } from 'wouter';
import { useQuery } from '@tanstack/react-query';
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Share2, Copy, ArrowLeft, ExternalLink, Lock, LogIn } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import DirectLogin from "@/components/direct-login";
import CommentsSection from "@/components/comments-section";
import type { Article } from "@shared/schema";

interface InfiniteArticleScrollProps {
  articles: Article[];
  initialArticleId?: number;
  onBack?: () => void;
}

export default function InfiniteArticleScroll({ articles, initialArticleId, onBack }: InfiniteArticleScrollProps) {
  const [, setLocation] = useLocation();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isScrolling, setIsScrolling] = useState(false);
  const { toast } = useToast();
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const containerRef = useRef<HTMLDivElement>(null);
  const startTouchY = useRef<number>(0);
  const currentTouchY = useRef<number>(0);

  // Find initial article index
  useEffect(() => {
    if (initialArticleId && articles.length > 0) {
      const index = articles.findIndex(article => article.id === initialArticleId);
      if (index >= 0) {
        setCurrentIndex(index);
      }
    }
  }, [initialArticleId, articles]);

  // Update URL when current article changes
  useEffect(() => {
    if (articles[currentIndex]) {
      const newUrl = `/article/${articles[currentIndex].id}`;
      setLocation(newUrl, { replace: true });
    }
  }, [currentIndex, articles, setLocation]);

  const getSentimentColor = (sentiment: string) => {
    switch (sentiment?.toLowerCase()) {
      case 'positive': return 'border-l-green-500 bg-green-50';
      case 'negative': return 'border-l-red-500 bg-red-50';
      default: return 'border-l-gray-500 bg-gray-50';
    }
  };

  const navigateArticle = useCallback((direction: 'next' | 'prev') => {
    if (isScrolling) return;

    setIsScrolling(true);

    if (direction === 'next' && currentIndex < articles.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else if (direction === 'prev' && currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }

    setTimeout(() => setIsScrolling(false), 300);
  }, [currentIndex, articles.length, isScrolling]);

  // Touch handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    startTouchY.current = e.touches[0].clientY;
    currentTouchY.current = e.touches[0].clientY;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    currentTouchY.current = e.touches[0].clientY;
  };

  const handleTouchEnd = () => {
    const deltaY = startTouchY.current - currentTouchY.current;
    const threshold = 50;

    if (Math.abs(deltaY) > threshold) {
      if (deltaY > 0) {
        navigateArticle('next');
      } else {
        navigateArticle('prev');
      }
    }
  };

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowDown' || e.key === ' ') {
        e.preventDefault();
        navigateArticle('next');
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        navigateArticle('prev');
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [navigateArticle]);

  // Mouse wheel handler
  const handleWheel = useCallback((e: WheelEvent) => {
    e.preventDefault();
    if (e.deltaY > 0) {
      navigateArticle('next');
    } else {
      navigateArticle('prev');
    }
  }, [navigateArticle]);

  // Wheel event listener
  useEffect(() => {
    const container = containerRef.current;
    if (container) {
      container.addEventListener('wheel', handleWheel, { passive: false });
      return () => container.removeEventListener('wheel', handleWheel);
    }
  }, [handleWheel]);

  const handleLoginPrompt = () => {
    toast({
      title: "Login Required",
      description: "Please login to access StocksShorts Special content. Other articles are free to read.",
      variant: "default",
    });
    setLocation("/profile");
  };

  if (!articles || articles.length === 0) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <p className="text-muted-foreground">No articles available</p>
      </div>
    );
  }

  const article = articles[currentIndex];
  if (!article) return null;

  const isSpecialArticle = article.type === 'StocksShorts Special';
  const isLocked = isSpecialArticle && !isAuthenticated;
  const shareableLink = `${window.location.origin}/article/${article.id}`;

  return (
    <div 
      ref={containerRef}
      className="min-h-screen bg-background overflow-hidden relative"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
    >
      {/* Header */}
      <div className="fixed top-0 left-0 right-0 bg-background/95 backdrop-blur border-b z-50">
        <div className="flex items-center justify-between p-4">
          <Button variant="ghost" size="sm" onClick={onBack}>
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back
          </Button>
          <div className="flex items-center space-x-2">
            <Badge variant="secondary" className="text-xs">
              {currentIndex + 1} of {articles.length}
            </Badge>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => navigator.clipboard.writeText(shareableLink)}
            >
              <Copy className="w-4 h-4" />
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => window.open(`https://api.whatsapp.com/send?text=${encodeURIComponent(shareableLink)}`, '_blank')}
            >
              <Share2 className="w-4 h-4" />
            </Button>
          </div>
        </div>
      </div>

      {/* Article Content */}
      <div className="pt-20 pb-8 px-4 min-h-screen flex flex-col">
        <Card className={`flex-1 ${getSentimentColor(article.sentiment || 'neutral')} border-l-4`}>
          <div className="p-6">
            {/* Article Type Badge */}
            <div className="flex items-center justify-between mb-4">
              <Badge variant="outline" className="text-xs">
                {article.type || 'NEWS'}
              </Badge>
              {isSpecialArticle && (
                <Badge className="bg-amber-500 hover:bg-amber-600 text-white">
                  StocksShorts Special
                </Badge>
              )}
            </div>

            {/* Title */}
            <h1 className="text-2xl font-bold text-foreground mb-4 leading-tight">
              {article.title}
            </h1>

            {/* Content */}
            <div className="text-foreground/80 leading-relaxed mb-6">
              {isLocked ? (
                <div className="space-y-3">
                  <div className="text-gray-400 dark:text-gray-500 text-sm">
                    {article.content.substring(0, 120)}...
                  </div>
                  <div className="bg-gradient-to-r from-amber-50 to-orange-50 dark:from-amber-900/20 dark:to-orange-900/20 rounded-lg border border-amber-200 dark:border-amber-800 p-3">
                    <div className="flex items-center justify-center mb-3">
                      <Lock className="h-5 w-5 text-amber-600 dark:text-amber-400 mr-2" />
                      <p className="text-base font-bold text-amber-800 dark:text-amber-200">
                        🔒 LOGIN TO READ this Special content
                      </p>
                    </div>
                    <DirectLogin />
                  </div>
                </div>
              ) : (
                <div dangerouslySetInnerHTML={{ __html: article.content.replace(/\n/g, '<br />') }} />
              )}
            </div>

            {/* Metadata */}
            <div className="flex items-center justify-between text-sm text-muted-foreground border-t pt-4">
              <span>{article.source}</span>
              <span>
                {new Date(article.time || article.createdAt).toLocaleDateString('en-IN', {
                  day: 'numeric',
                  month: 'short',
                  year: 'numeric'
                })}
              </span>
            </div>

            {/* Comments Section - Only for Trader View articles */}
            {article.type === 'Trader View' && (
              <div className="mt-6 pt-6 border-t border-gray-200 dark:border-gray-700">
                <div className="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-lg mb-4">
                  <h3 className="text-lg font-semibold text-blue-800 dark:text-blue-200">Chart Discussion</h3>
                  <p className="text-sm text-blue-600 dark:text-blue-400 mt-1">
                    Share your analysis and discuss this chart with other traders
                  </p>
                </div>
                <CommentsSection articleId={article.id} articleTitle={article.title} />
              </div>
            )}
          </div>
        </Card>

        {/* Navigation hints */}
        <div className="text-center text-xs text-muted-foreground mt-4 space-y-1">
          <p>Swipe up/down or use arrow keys to navigate</p>
          <div className="flex justify-center space-x-4">
            {currentIndex > 0 && (
              <span>↑ Previous article</span>
            )}
            {currentIndex < articles.length - 1 && (
              <span>↓ Next article</span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

server/services/financialDataProvider.ts.content:
// Professional financial data provider for Indian stocks
// Supports multiple authentic data sources with fallback hierarchy

interface FinancialData {
  symbol: string;
  currentPrice?: number;
  marketCap?: number;
  pe?: number;
  pb?: number;
  roe?: number;
  debtToEquity?: number;
  eps?: number;
  bookValue?: number;
  profitMargin?: number;
  revenueGrowth?: number;
  sector?: string;
  industry?: string;
  source: string;
  lastUpdated: Date;
  conferenceCallData?: any; // Conference call and management guidance data
}

export class FinancialDataProvider {
  private cache = new Map<string, { data: FinancialData; timestamp: number }>();
  private cacheTimeout = 5 * 60 * 1000; // 5 minutes cache

  // Major Indian stock symbol mappings
  private stockMappings: { [key: string]: string } = {
    'TCS': 'TCS.NS',
    'RELIANCE': 'RELIANCE.NS',
    'HDFCBANK': 'HDFCBANK.NS',
    'INFY': 'INFY.NS',
    'ICICIBANK': 'ICICIBANK.NS',
    'HINDUNILVR': 'HINDUNILVR.NS',
    'ITC': 'ITC.NS',
    'SBIN': 'SBIN.NS',
    'BAJFINANCE': 'BAJFINANCE.NS',
    'BHARTIARTL': 'BHARTIARTL.NS',
    'ASIANPAINT': 'ASIANPAINT.NS',
    'MARUTI': 'MARUTI.NS',
    'KOTAKBANK': 'KOTAKBANK.NS',
    'LT': 'LT.NS',
    'AXISBANK': 'AXISBANK.NS',
    'NESTLEIND': 'NESTLEIND.NS',
    'HDFC': 'HDFC.NS',
    'WIPRO': 'WIPRO.NS',
    'ULTRACEMCO': 'ULTRACEMCO.NS',
    'TITAN': 'TITAN.NS'
  };

  async getFinancialData(symbol: string): Promise<FinancialData | null> {
    // Check cache first
    const cached = this.cache.get(symbol);
    if (cached && Date.now() - cached.timestamp < this.cacheTimeout) {
      return cached.data;
    }

    try {
      // 1. Try real Indian stock data provider (authentic market data)
      const { realIndianStockDataProvider } = await import('./realIndianStockData');
      const realData = await realIndianStockDataProvider.getRealStockData(symbol);
      if (realData) {
        console.log(`Real market data retrieved for ${symbol}: ₹${realData.currentPrice}, PE ${realData.pe}, ROE ${realData.roe}% from ${realData.source}`);

        const financialData: FinancialData = {
          symbol: realData.symbol,
          currentPrice: realData.currentPrice,
          marketCap: realData.marketCap,
          pe: realData.pe,
          pb: realData.pb,
          roe: realData.roe ? realData.roe / 100 : undefined, // Convert percentage to decimal
          debtToEquity: realData.debtToEquity,
          eps: realData.eps,
          bookValue: realData.bookValue,
          profitMargin: realData.profitMargin,
          sector: realData.sector,
          industry: realData.industry,
          source: realData.source,
          lastUpdated: realData.lastUpdated
        };

        this.cache.set(symbol, { data: financialData, timestamp: Date.now() });
        return financialData;
      }

      console.log(`No financial data available for ${symbol}`);
      return null;
    } catch (error) {
      console.log(`Error fetching financial data for ${symbol}:`, error);
      return null;
    }
  }

  private async fetchFromNSE(symbol: string): Promise<FinancialData | null> {
    try {
      const { nseService } = await import('./nseService');
      const nseData = await nseService.getStockQuote(symbol);

      if (nseData) {
        return {
          symbol,
          currentPrice: nseData.lastPrice,
          marketCap: nseData.marketCap,
          pe: nseData.pe,
          pb: nseData.pb,
          sector: undefined,
          industry: nseData.industry,
          source: 'NSE India',
          lastUpdated: new Date()
        };
      }

      return null;
    } catch (error) {
      console.log(`NSE error for ${symbol}:`, error);
      return null;
    }
  }

  private async fetchFromScreener(symbol: string): Promise<FinancialData | null> {
    try {
      const { screenerService } = await import('./screenerService');
      const screenerData = await screenerService.getStockByName(symbol);

      if (screenerData) {
        return {
          symbol,
          currentPrice: screenerData.currentPrice,
          marketCap: screenerData.marketCap,
          pe: screenerData.pe,
          pb: screenerData.pb,
          roe: screenerData.roe / 100, // Convert percentage to decimal
          debtToEquity: screenerData.debtToEquity,
          sector: screenerData.sector,
          industry: screenerData.industry,
          source: 'Screener.in',
          lastUpdated: new Date()
        };
      }

      return null;
    } catch (error) {
      console.log(`Screener.in error for ${symbol}:`, error);
      return null;
    }
  }

  private async fetchFromYahooFinance(symbol: string): Promise<FinancialData | null> {
    try {
      const yahooSymbol = this.stockMappings[symbol] || `${symbol}.NS`;
      console.log(`Attempting Yahoo Finance for ${yahooSymbol}`);

      const response = await fetch(
        `https://query1.finance.yahoo.com/v10/finance/quoteSummary/${yahooSymbol}?modules=summaryDetail,financialData,defaultKeyStatistics,earnings`,
        {
          headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
            'Accept': 'application/json',
            'Accept-Language': 'en-US,en;q=0.9',
            'Accept-Encoding': 'gzip, deflate, br',
            'Connection': 'keep-alive',
            'Sec-Fetch-Dest': 'empty',
            'Sec-Fetch-Mode': 'cors',
            'Sec-Fetch-Site': 'same-site'
          }
        }
      );

      if (!response.ok) {
        console.log(`Yahoo Finance failed for ${yahooSymbol}: ${response.status}`);
        return null;
      }

      const data = await response.json();
      const result = data.quoteSummary?.result?.[0];
      if (!result) {
        console.log(`No data in Yahoo Finance response for ${yahooSymbol}`);
        return null;
      }

      const summary = result.summaryDetail || {};
      const financial = result.financialData || {};
      const keyStats = result.defaultKeyStatistics || {};
      const earnings = result.earnings || {};

      const extractedData = {
        symbol,
        currentPrice: summary.regularMarketPrice?.raw || summary.previousClose?.raw || 0,
        marketCap: summary.marketCap?.raw,
        pe: summary.trailingPE?.raw || summary.forwardPE?.raw,
        pb: keyStats.priceToBook?.raw,
        eps: keyStats.trailingEps?.raw,
        bookValue: keyStats.bookValue?.raw,
        roe: financial.returnOnEquity?.raw,
        debtToEquity: financial.debtToEquity?.raw,
        profitMargin: financial.profitMargins?.raw,
        revenueGrowth: financial.revenueGrowth?.raw,
        sector: summary.sector,
        industry: summary.industry,
        source: 'Yahoo Finance',
        lastUpdated: new Date()
      };

      // Filter out null/undefined values
      const cleanData = Object.fromEntries(
        Object.entries(extractedData).filter(([_, value]) => value !== null && value !== undefined)
      ) as FinancialData;

      console.log(`Yahoo Finance success for ${symbol}: ${Object.keys(cleanData).length} metrics`);
      return cleanData;
    } catch (error) {
      console.log(`Yahoo Finance error for ${symbol}:`, error);
      return null;
    }
  }



  private async fetchFromGPTSearch(symbol: string): Promise<FinancialData | null> {
    if (!process.env.OPENAI_API_KEY) return null;

    try {
      console.log(`Using GPT-3.5-turbo to extract financial data for ${symbol}`);

      const openai = new (await import('openai')).default({
        apiKey: process.env.OPENAI_API_KEY
      });

      const prompt = `Extract current financial data for ${symbol} (Indian NSE/BSE stock). Provide exact numerical data in JSON format:
      {
        "currentPrice": number (in rupees),
        "pe": number (PE ratio),
        "marketCap": number (in crores),
        "roe": number (as decimal, e.g., 0.15 for 15%),
        "debtToEquity": number,
        "profitMargin": number (as decimal),
        "eps": number,
        "bookValue": number,
        "pb": number (price to book ratio),
        "sector": "string",
        "industry": "string"
      }
      Search for authentic data from financial websites. If specific data unavailable, set to null. Focus on current accurate numbers.`;

      const response = await openai.chat.completions.create({
        model: "gpt-3.5-turbo",
        messages: [{ role: "user", content: prompt }],
        response_format: { type: "json_object" },
        max_tokens: 500
      });

      if (response.choices[0].message.content) {
        const data = JSON.parse(response.choices[0].message.content);

        // Validate that we have meaningful data
        const hasValidData = data.currentPrice > 0 || data.pe > 0 || data.marketCap > 0;

        if (hasValidData) {
          console.log(`GPT extracted financial data for ${symbol}: ${Object.keys(data).length} metrics`);

          return {
            symbol,
            currentPrice: data.currentPrice || undefined,
            pe: data.pe || undefined,
            marketCap: data.marketCap || undefined,
            roe: data.roe || undefined,
            debtToEquity: data.debtToEquity || undefined,
            profitMargin: data.profitMargin || undefined,
            eps: data.eps || undefined,
            bookValue: data.bookValue || undefined,
            pb: data.pb || undefined,
            sector: data.sector || undefined,
            industry: data.industry || undefined,
            source: 'GPT-3.5-turbo Financial Search',
            lastUpdated: new Date()
          };
        }
      }

      console.log(`GPT: No meaningful financial data found for ${symbol}`);
      return null;
    } catch (error) {
      console.log(`GPT search error for ${symbol}:`, error);
      return null;
    }
  }

  private async fetchFromFMP(symbol: string): Promise<FinancialData | null> {
    if (!process.env.FMP_API_KEY) return null;

    try {
      console.log(`Attempting Financial Modeling Prep for ${symbol}`);

      const response = await fetch(
        `https://financialmodelingprep.com/api/v3/profile/${symbol}.NS?apikey=${process.env.FMP_API_KEY}`
      );

      if (!response.ok) return null;

      const data = await response.json();
      if (!data[0]) return null;

      const profile = data[0];
      return {
        symbol,
        currentPrice: profile.price || 0,
        marketCap: profile.mktCap,
        pe: profile.pe,
        eps: profile.eps,
        pb: profile.pb,
        sector: profile.sector,
        industry: profile.industry,
        source: 'Financial Modeling Prep',
        lastUpdated: new Date()
      };
    } catch (error) {
      console.log(`FMP error for ${symbol}:`, error);
      return null;
    }
  }

  async testMultipleStocks(symbols: string[]): Promise<{ [key: string]: FinancialData | null }> {
    const results: { [key: string]: FinancialData | null } = {};

    for (const symbol of symbols) {
      results[symbol] = await this.getFinancialData(symbol);
    }

    return results;
  }

  clearCache(): void {
    this.cache.clear();
  }
}

export const financialDataProvider = new FinancialDataProvider();

server/services/gmailTracker.ts.content:
import { google } from 'googleapis';
import { GoogleGenAI } from '@google/genai';
import { storage } from '../storage';

interface EmailInsight {
  companies: string[];
  sectors: string[];
  keywords: string[];
  sentiment: 'Positive' | 'Negative' | 'Neutral';
  topics: string[];
}

interface PersonalizedArticle {
  title: string;
  content: string;
  source: string;
  type: string;
  sentiment: 'Positive' | 'Negative' | 'Neutral';
  priority: '1' | '2' | '3' | '4' | '5';
  newsDate: Date;
  personalizationReason: string;
}

export class GmailTracker {
  private gmail: any;
  private genai: GoogleGenAI;
  private isInitialized = false;

  constructor() {
    this.genai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY || "" });
  }

  async initialize(credentials: any) {
    try {
      const auth = new google.auth.OAuth2(
        process.env.GMAIL_CLIENT_ID,
        process.env.GMAIL_CLIENT_SECRET,
        process.env.GMAIL_REDIRECT_URI
      );

      auth.setCredentials(credentials);
      this.gmail = google.gmail({ version: 'v1', auth });
      this.isInitialized = true;

      console.log('Gmail API initialized successfully');
      return true;
    } catch (error) {
      console.error('Gmail initialization failed:', error);
      return false;
    }
  }

  async getAuthUrl(): Promise<string> {
    const auth = new google.auth.OAuth2(
      process.env.GMAIL_CLIENT_ID,
      process.env.GMAIL_CLIENT_SECRET,
      process.env.GMAIL_REDIRECT_URI
    );

    const scopes = [
      'https://www.googleapis.com/auth/gmail.readonly',
      'https://www.googleapis.com/auth/gmail.labels'
    ];

    const url = auth.generateAuthUrl({
      access_type: 'offline',
      scope: scopes,
    });

    return url;
  }

  async exchangeCodeForTokens(code: string) {
    const auth = new google.auth.OAuth2(
      process.env.GMAIL_CLIENT_ID,
      process.env.GMAIL_CLIENT_SECRET,
      process.env.GMAIL_REDIRECT_URI
    );

    const { tokens } = await auth.getToken(code);
    return tokens;
  }

  async scanRecentEmails(maxResults: number = 50): Promise<EmailInsight> {
    if (!this.isInitialized) {
      throw new Error('Gmail API not initialized');
    }

    try {
      // Get recent emails from last 7 days
      const query = `newer_than:7d`;
      const response = await this.gmail.users.messages.list({
        userId: 'me',
        q: query,
        maxResults: maxResults
      });

      const messages = response.data.messages || [];
      const emailContents: string[] = [];

      // Fetch email content
      for (const message of messages.slice(0, 20)) { // Limit to 20 for performance
        try {
          const messageData = await this.gmail.users.messages.get({
            userId: 'me',
            id: message.id,
            format: 'full'
          });

          const subject = this.extractHeader(messageData.data, 'Subject') || '';
          const body = this.extractEmailBody(messageData.data) || '';

          if (subject || body) {
            emailContents.push(`Subject: ${subject}\nBody: ${body.substring(0, 1000)}`);
          }
        } catch (err) {
          console.log('Error fetching message:', err);
        }
      }

      // Analyze emails with AI
      return await this.analyzeEmailContent(emailContents);
    } catch (error) {
      console.error('Error scanning emails:', error);
      throw error;
    }
  }

  private extractHeader(message: any, headerName: string): string | null {
    const headers = message.payload?.headers || [];
    const header = headers.find((h: any) => h.name === headerName);
    return header?.value || null;
  }

  private extractEmailBody(message: any): string {
    let body = '';

    if (message.payload?.body?.data) {
      body = Buffer.from(message.payload.body.data, 'base64').toString();
    } else if (message.payload?.parts) {
      for (const part of message.payload.parts) {
        if (part.mimeType === 'text/plain' && part.body?.data) {
          body += Buffer.from(part.body.data, 'base64').toString();
        }
      }
    }

    return body.replace(/<[^>]*>/g, ''); // Remove HTML tags
  }

  private async analyzeEmailContent(emailContents: string[]): Promise<EmailInsight> {
    if (emailContents.length === 0) {
      return {
        companies: [],
        sectors: [],
        keywords: [],
        sentiment: 'Neutral',
        topics: []
      };
    }

    const combinedContent = emailContents.join('\n\n');

    const prompt = `
    Analyze the following email content for Indian stock market interests:

    ${combinedContent}

    Extract and return JSON with:
    {
      "companies": ["list of Indian company names mentioned"],
      "sectors": ["sectors like Banking, IT, Pharma, Auto, etc."],
      "keywords": ["investment keywords like IPO, dividend, earnings, etc."],
      "sentiment": "Positive/Negative/Neutral overall sentiment",
      "topics": ["main financial topics discussed"]
    }

    Focus only on Indian stock market related content. Ignore promotional emails.
    `;

    try {
      const response = await this.genai.models.generateContent({
        model: "gemini-2.5-flash",
        config: {
          responseMimeType: "application/json",
        },
        contents: prompt,
      });

      const analysis = JSON.parse(response.text || '{}');

      return {
        companies: analysis.companies || [],
        sectors: analysis.sectors || [],
        keywords: analysis.keywords || [],
        sentiment: analysis.sentiment || 'Neutral',
        topics: analysis.topics || []
      };
    } catch (error) {
      console.error('Error analyzing email content:', error);
      return {
        companies: [],
        sectors: [],
        keywords: [],
        sentiment: 'Neutral',
        topics: []
      };
    }
  }

  async generatePersonalizedArticles(insights: EmailInsight): Promise<PersonalizedArticle[]> {
    if (insights.companies.length === 0 && insights.sectors.length === 0) {
      return [];
    }

    const prompt = `
    Generate 5 personalized corporate announcements based on user's email interests:

    User's Interests:
    - Companies: ${insights.companies.join(', ')}
    - Sectors: ${insights.sectors.join(', ')}
    - Keywords: ${insights.keywords.join(', ')}
    - Topics: ${insights.topics.join(', ')}

    Create realistic corporate announcements (warrant issues, conference calls, order wins, SEBI alerts, preferential issues) focusing on these companies/sectors.

    Return JSON array with format:
    [{
      "title": "Date: Company/Event Title",
      "content": "Detailed announcement with specific numbers and dates",
      "source": "Official source like NSE, BSE, Company IR",
      "type": "AI News",
      "sentiment": "Positive/Negative/Neutral",
      "priority": "1-5",
      "newsDate": "2025-06-29",
      "personalizationReason": "Based on your interest in [Company/Sector]"
    }]

    Make announcements realistic with proper Indian company names, deal values in crores, and authentic corporate language.
    `;

    try {
      const response = await this.genai.models.generateContent({
        model: "gemini-2.5-pro",
        config: {
          responseMimeType: "application/json",
        },
        contents: prompt,
      });

      const articles = JSON.parse(response.text || '[]');

      return articles.map((article: any) => ({
        ...article,
        newsDate: new Date(article.newsDate)
      }));
    } catch (error) {
      console.error('Error generating personalized articles:', error);
      return [];
    }
  }

  async processEmailTracking(): Promise<void> {
    try {
      console.log('Starting email tracking process...');

      // Scan recent emails
      const insights = await this.scanRecentEmails();
      console.log('Email insights extracted:', insights);

      // Generate personalized articles
      const personalizedArticles = await this.generatePersonalizedArticles(insights);
      console.log(`Generated ${personalizedArticles.length} personalized articles`);

      if (personalizedArticles.length > 0) {
        // Add userId to each article and store
        const articlesWithUserId = personalizedArticles.map(article => ({
          ...article,
          userId: 1 // Default user ID for now, will be dynamic when user authentication is added
        }));
        await storage.storePersonalizedArticles(articlesWithUserId);
        console.log('Personalized articles stored successfully');
      }
    } catch (error) {
      console.error('Email tracking process failed:', error);
    }
  }

  async getPersonalizedArticles(limit: number = 10): Promise<any[]> {
    return await storage.getPersonalizedArticles(limit);
  }
}

