    description: 'Investment disclaimer, terms of service, and important legal information for StocksShorts users.',
    keywords: 'investment disclaimer, terms of service, legal information'
  }
};

export function SEOWrapper({ children, articles }: SEOWrapperProps) {
  const [location] = useLocation();

  useEffect(() => {
    const config = seoPages[location as keyof typeof seoPages] || seoPages['/'];

    // Update page title
    document.title = config.title;

    // Update meta description
    updateMeta('description', config.description);

    // Update meta keywords
    updateMeta('keywords', config.keywords);

    // Update canonical URL
    const canonical = `https://stocksshorts.com${location}`;
    updateCanonical(canonical);

    // Update Open Graph tags
    updateMeta('og:title', config.title, 'property');
    updateMeta('og:description', config.description, 'property');
    updateMeta('og:url', canonical, 'property');

    // Update Twitter Card tags
    updateMeta('twitter:title', config.title);
    updateMeta('twitter:description', config.description);

    // Add article structured data for news pages
    if (articles && articles.length > 0) {
      addArticleStructuredData(articles[0]);
    }

  }, [location, articles]);

  return <>{children}</>;
}

function updateMeta(name: string, content: string, attribute: string = 'name') {
  let meta = document.querySelector(`meta[${attribute}="${name}"]`);
  if (!meta) {
    meta = document.createElement('meta');
    meta.setAttribute(attribute, name);
    document.head.appendChild(meta);
  }
  meta.setAttribute('content', content);
}

function updateCanonical(url: string) {
  let canonical = document.querySelector('link[rel="canonical"]');
  if (!canonical) {
    canonical = document.createElement('link');
    canonical.setAttribute('rel', 'canonical');
    document.head.appendChild(canonical);
  }
  canonical.setAttribute('href', url);
}

function addArticleStructuredData(article: Article) {
  const schema = {
    "@context": "https://schema.org",
    "@type": "NewsArticle",
    "headline": article.title,
    "description": article.content.substring(0, 160) + "...",
    "articleBody": article.content,
    "datePublished": article.time || article.createdAt,
    "dateModified": article.createdAt,
    "author": {
      "@type": "Organization",
      "name": article.source || "StocksShorts"
    },
    "publisher": {
      "@type": "Organization",
      "name": "StocksShorts",
      "logo": {
        "@type": "ImageObject",
        "url": "https://stocksshorts.com/favicon.ico"
      }
    },
    "mainEntityOfPage": {
      "@type": "WebPage",
      "@id": `https://stocksshorts.com/article/${article.id}`
    },
    "articleSection": article.type || "Stock Market News",
    "keywords": getKeywordsFromArticle(article)
  };

  // Remove existing article schema
  const existingScript = document.getElementById('article-schema');
  if (existingScript) {
    existingScript.remove();
  }

  // Add new schema
  const script = document.createElement('script');
  script.id = 'article-schema';
  script.type = 'application/ld+json';
  script.textContent = JSON.stringify(schema);
  document.head.appendChild(script);
}

function getKeywordsFromArticle(article: Article): string {
  const keywords = [];

  // Add category-based keywords
  switch (article.type?.toLowerCase()) {
    case 'nifty':
      keywords.push('Nifty 50', 'NSE', 'Indian stock index');
      break;
    case 'breakout stock':
      keywords.push('stock breakout', 'technical analysis', 'trading signals');
      break;
    case 'ipo':
      keywords.push('IPO', 'initial public offering', 'new listings');
      break;
    case 'global':
      keywords.push('global markets', 'international impact', 'foreign investment');
      break;
    default:
      keywords.push('Indian stocks', 'stock market news');
  }

  // Add sentiment-based keywords
  if (article.sentiment) {
    keywords.push(`${article.sentiment.toLowerCase()} market sentiment`);
  }

  return keywords.join(', ');
}

