        timestamp: new Date().toISOString()
      });
    } catch (error) {
      console.error('Stock testing error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Stock testing failed'
      });
    }
  });

  // Test specific stocks with financial data extraction
  app.post("/api/stock-testing/test-stocks", async (req, res) => {
    try {
      const { symbols } = req.body;

      if (!symbols || !Array.isArray(symbols)) {
        return res.status(400).json({ message: 'Symbols array is required' });
      }

      console.log(`Testing ${symbols.length} specific stocks:`, symbols);
      const results = await stockTester.testSpecificStocks(symbols);

      res.json({
        message: `Testing completed for ${symbols.length} stocks`,
        results,
        timestamp: new Date().toISOString()
      });
    } catch (error) {
      console.error('Specific stock testing error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Stock testing failed'
      });
    }
  });

  // Validate data quality for a specific stock
  app.get("/api/stock-testing/validate/:symbol", async (req, res) => {
    try {
      const { symbol } = req.params;

      if (!symbol) {
        return res.status(400).json({ message: 'Stock symbol is required' });
      }

      console.log(`Validating data quality for ${symbol}...`);
      const validation = await stockTester.validateDataQuality(symbol.toUpperCase());

      res.json({
        message: `Data quality validation for ${symbol}`,
        validation,
        timestamp: new Date().toISOString()
      });
    } catch (error) {
      console.error('Data validation error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Data validation failed'
      });
    }
  });

  // Get financial data for any stock using multiple providers
  app.get("/api/financial-data/:symbol", async (req, res) => {
    try {
      const { symbol } = req.params;

      if (!symbol) {
        return res.status(400).json({ message: 'Stock symbol is required' });
      }

      console.log(`Fetching comprehensive financial data for ${symbol}...`);
      const data = await financialDataProvider.getFinancialData(symbol.toUpperCase());

      if (data) {
        res.json({
          message: `Financial data retrieved for ${symbol}`,
          data,
          timestamp: new Date().toISOString()
        });
      } else {
        res.status(404).json({
          message: `No financial data available for ${symbol}`,
          timestamp: new Date().toISOString()
        });
      }
    } catch (error) {
      console.error('Financial data error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Financial data retrieval failed'
      });
    }
  });

  // Conference Call and Management Guidance Endpoints

  // Get conference call transcripts and management guidance
  app.get("/api/conference-calls/:symbol", async (req, res) => {
    try {
      const { symbol } = req.params;

      if (!symbol) {
        return res.status(400).json({ message: 'Stock symbol is required' });
      }

      console.log(`Fetching conference call data for ${symbol}...`);
      const data = await conferenceCallService.getConferenceCallData(symbol.toUpperCase());

      if (data) {
        res.json({
          message: `Conference call data retrieved for ${symbol}`,
          data,
          timestamp: new Date().toISOString()
        });
      } else {
        res.status(404).json({
          message: `No conference call data available for ${symbol}`,
          timestamp: new Date().toISOString()
        });
      }
    } catch (error) {
      console.error('Conference call data error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Conference call data retrieval failed'
      });
    }
  });

  // Get management guidance and recent news
  app.get("/api/management-guidance/:symbol", async (req, res) => {
    try {
      const { symbol } = req.params;

      if (!symbol) {
        return res.status(400).json({ message: 'Stock symbol is required' });
      }

      console.log(`Fetching management guidance for ${symbol}...`);
      const conferenceData = await conferenceCallService.getConferenceCallData(symbol.toUpperCase());

      if (conferenceData) {
        const guidanceData = {
          symbol: symbol.toUpperCase(),
          revenueGrowthTarget: conferenceData.revenueGrowthTarget,
          marginExpansion: conferenceData.marginExpansion,
          capexGuidance: conferenceData.capexGuidance,
          managementOutlook: conferenceData.managementOutlook,
          industryCommentary: conferenceData.industryCommentary,
          source: conferenceData.source,
          lastUpdated: conferenceData.lastUpdated
        };

        res.json({
          message: `Management guidance retrieved for ${symbol}`,
          data: guidanceData,
          timestamp: new Date().toISOString()
        });
      } else {
        res.status(404).json({
          message: `No management guidance available for ${symbol}`,
          timestamp: new Date().toISOString()
        });
      }
    } catch (error) {
      console.error('Management guidance error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Management guidance retrieval failed'
      });
    }
  });

  // Get recent company news and developments
  app.get("/api/company-news/:symbol", async (req, res) => {
    try {
      const { symbol } = req.params;

      if (!symbol) {
        return res.status(400).json({ message: 'Stock symbol is required' });
      }

      console.log(`Fetching recent company news for ${symbol}...`);
      const conferenceData = await conferenceCallService.getConferenceCallData(symbol.toUpperCase());

      if (conferenceData && conferenceData.recentNews) {
        const newsData = {
          symbol: symbol.toUpperCase(),
          recentNews: conferenceData.recentNews,
          quarterlyHighlights: conferenceData.quarterlyHighlights,
          source: conferenceData.source,
          lastUpdated: conferenceData.lastUpdated
        };

        res.json({
          message: `Recent company news retrieved for ${symbol}`,
          data: newsData,
          timestamp: new Date().toISOString()
        });
      } else {
        res.status(404).json({
          message: `No recent company news available for ${symbol}`,
          timestamp: new Date().toISOString()
        });
      }
    } catch (error) {
      console.error('Company news error:', error);
      res.status(500).json({
        message: error instanceof Error ? error.message : 'Company news retrieval failed'
      });
    }
  });

  // AI news system removed - focusing on Google Sheets content only

  // Gmail integration endpoints
  app.get("/api/gmail/auth-url", async (req, res) => {
    try {
      const authUrl = await gmailTracker.getAuthUrl();
      res.json({ authUrl });
    } catch (error) {
      console.error("Error generating Gmail auth URL:", error);
      res.status(500).json({ message: "Failed to generate auth URL" });
    }
  });

  app.post("/api/gmail/callback", async (req, res) => {
    try {
      const { code, userId } = req.body;

      if (!code) {
        return res.status(400).json({ message: "Authorization code required" });
      }

      // Exchange code for tokens
      const tokens = await gmailTracker.exchangeCodeForTokens(code);

      // Store credentials
      await storage.storeGmailCredentials({
        userId: userId || 1, // Default to user 1 for now
        accessToken: tokens.access_token!,
        refreshToken: tokens.refresh_token || null,
        expiryDate: tokens.expiry_date ? new Date(tokens.expiry_date) : null,
        isActive: true,
      });

      // Initialize Gmail tracker
      await gmailTracker.initialize(tokens);

      res.json({ success: true, message: "Gmail connected successfully" });
    } catch (error) {
      console.error("Error handling Gmail callback:", error);
      res.status(500).json({ message: "Failed to connect Gmail" });
    }
  });

  app.post("/api/gmail/scan", async (req, res) => {
    try {
      // Get user credentials
      const credentials = await storage.getGmailCredentials(1); // Default user 1

      if (!credentials) {
        return res.status(400).json({ message: "Gmail not connected. Please connect your Gmail first." });
      }

      // Initialize and scan emails
      await gmailTracker.initialize({
        access_token: credentials.accessToken,
        refresh_token: credentials.refreshToken,
        expiry_date: credentials.expiryDate?.getTime(),
      });

      await gmailTracker.processEmailTracking();

      res.json({ success: true, message: "Email scanning completed" });
    } catch (error) {
      console.error("Error scanning emails:", error);
      res.status(500).json({ message: "Failed to scan emails" });
    }
  });

  app.get("/api/personalized-articles", async (req, res) => {
    try {
      const limit = parseInt(req.query.limit as string) || 10;
      const articles = await storage.getPersonalizedArticles(limit);
      res.json(articles);
    } catch (error) {
      console.error("Error fetching personalized articles:", error);
      res.status(500).json({ message: "Failed to fetch personalized articles" });
    }
  });

  // Serve attached assets from a different path to avoid conflict with build assets
  app.get('/attachments/:filename', (req, res) => {
    const { filename } = req.params;
    const filePath = path.join(process.cwd(), 'attached_assets', filename);

    // Check if file exists
    if (!fs.existsSync(filePath)) {
      return res.status(404).json({ error: 'Asset not found' });
    }

    // Serve the file with proper content type
    res.sendFile(filePath);
  });

  const httpServer = createServer(app);
  return httpServer;
}

stocksshorts-backup/client/src/index.css.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --background: hsl(0, 0%, 100%);
  --foreground: hsl(20, 14.3%, 4.1%);
  --muted: hsl(60, 4.8%, 95.9%);
  --muted-foreground: hsl(25, 5.3%, 44.7%);
  --popover: hsl(0, 0%, 100%);
  --popover-foreground: hsl(20, 14.3%, 4.1%);
  --card: hsl(0, 0%, 100%);
  --card-foreground: hsl(20, 14.3%, 4.1%);
  --border: hsl(20, 5.9%, 90%);
  --input: hsl(20, 5.9%, 90%);
  --primary: hsl(214, 84%, 56%);
  --primary-foreground: hsl(211, 100%, 99%);
  --secondary: hsl(60, 4.8%, 95.9%);
  --secondary-foreground: hsl(24, 9.8%, 10%);
  --accent: hsl(60, 4.8%, 95.9%);
  --accent-foreground: hsl(24, 9.8%, 10%);
  --destructive: hsl(0, 84.2%, 60.2%);
  --destructive-foreground: hsl(60, 9.1%, 97.8%);
  --ring: hsl(20, 14.3%, 4.1%);
  --radius: 0.5rem;

  /* Custom colors for financial themes */
  --success: hsl(142, 71%, 45%);
  --danger: hsl(0, 84.2%, 60.2%);
  --warning: hsl(38, 92%, 50%);
  --info: hsl(214, 84%, 56%);

  /* Neutral colors */
  --neutral-50: hsl(210, 40%, 98%);
  --neutral-100: hsl(210, 40%, 96%);
  --neutral-200: hsl(214, 32%, 91%);
  --neutral-300: hsl(213, 27%, 84%);
  --neutral-400: hsl(215, 20%, 65%);
  --neutral-500: hsl(215, 16%, 47%);
  --neutral-600: hsl(215, 19%, 35%);
  --neutral-700: hsl(215, 25%, 27%);
  --neutral-800: hsl(217, 33%, 17%);
  --neutral-900: hsl(222, 84%, 5%);
}

.dark {
  --background: hsl(240, 10%, 3.9%);
  --foreground: hsl(0, 0%, 98%);
  --muted: hsl(240, 3.7%, 15.9%);
  --muted-foreground: hsl(240, 5%, 64.9%);
  --popover: hsl(240, 10%, 3.9%);
  --popover-foreground: hsl(0, 0%, 98%);
  --card: hsl(240, 10%, 3.9%);
  --card-foreground: hsl(0, 0%, 98%);
  --border: hsl(240, 3.7%, 15.9%);
  --input: hsl(240, 3.7%, 15.9%);
  --primary: hsl(214, 84%, 56%);
  --primary-foreground: hsl(211, 100%, 99%);
  --secondary: hsl(240, 3.7%, 15.9%);
  --secondary-foreground: hsl(0, 0%, 98%);
  --accent: hsl(240, 3.7%, 15.9%);
  --accent-foreground: hsl(0, 0%, 98%);
  --destructive: hsl(0, 62.8%, 30.6%);
  --destructive-foreground: hsl(0, 0%, 98%);
  --ring: hsl(240, 4.9%, 83.9%);
  --radius: 0.5rem;
}

/* Special shimmer effect for StocksShorts Special category */
.special-shimmer::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.4),
    transparent
  );
  animation: shimmer 2s infinite;
}

@keyframes shimmer {
  0% {
    left: -100%;
  }
  100% {
    left: 100%;
  }
}

@keyframes scroll {
  0% {
    transform: translateX(100%);
  }
  100% {
    transform: translateX(-100%);
  }
}

@keyframes fadeInUp {
  0% {
    opacity: 0;
    transform: translateY(30px);
  }
  100% {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-scroll {
  animation: scroll 60s linear infinite;
}

/* News ticker styles for SEBI RIA directory */
.ticker-wrapper {
  width: 100%;
  overflow: hidden;
}

.ticker-content {
  display: inline-block;
  white-space: nowrap;
  animation: ticker 300s linear infinite;
}

/* Modal animations */
@keyframes modalEnter {
  0% {
    opacity: 0;
    transform: scale(0.9) translateY(10px);
  }
  100% {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@keyframes modalExit {
  0% {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
  100% {
    opacity: 0;
    transform: scale(0.9) translateY(10px);
  }
}

.modal-content {
  animation: modalEnter 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

.modal-content[data-state="closed"] {
  animation: modalExit 0.2s cubic-bezier(0.16, 1, 0.3, 1);
}

/* Custom scrollbar for modal content */
.modal-scroll::-webkit-scrollbar {
  width: 8px;
}

.modal-scroll::-webkit-scrollbar-track {
  background: transparent;
}

.modal-scroll::-webkit-scrollbar-thumb {
  background: rgb(209 213 219);
  border-radius: 4px;
}

.dark .modal-scroll::-webkit-scrollbar-thumb {
  background: rgb(75 85 99);
}

.modal-scroll::-webkit-scrollbar-thumb:hover {
  background: rgb(156 163 175);
}

.dark .modal-scroll::-webkit-scrollbar-thumb:hover {
  background: rgb(107 114 128);
}

/* Responsive modal adjustments */
@media (max-width: 768px) {
  .modal-content {
    width: 95vw !important;
    height: 95vh !important;
    max-height: 95vh !important;
    margin: 2.5vh auto;
  }
}

@keyframes ticker {
  0% {
    transform: translateX(100%);
  }
  100% {
    transform: translateX(-100%);
  }
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;
  }
}

@layer utilities {
  .scrollbar-hide {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .scrollbar-hide::-webkit-scrollbar {
    display: none;
  }

  .line-clamp-4 {
    overflow: hidden;
    display: -webkit-box;
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 4;
  }

  .text-success {
    color: var(--success);
  }

  .text-danger {
    color: var(--danger);
  }

  .text-warning {
    color: var(--warning);
  }

  .text-info {
    color: var(--info);
  }

  .bg-success {
    background-color: var(--success);
  }

  .bg-danger {
    background-color: var(--danger);
  }

  .bg-warning {
    background-color: var(--warning);
  }

  .bg-info {
    background-color: var(--info);
  }

  .bg-success\/10 {
    background-color: hsl(142, 71%, 45%, 0.1);
  }

  .bg-danger\/10 {
    background-color: hsl(0, 84.2%, 60.2%, 0.1);
  }

  .bg-primary\/10 {
    background-color: hsl(214, 84%, 56%, 0.1);
  }

  .border-l-success {
    border-left-color: var(--success);
  }

  .border-l-danger {
    border-left-color: var(--danger);
  }

  .border-l-primary {
    border-left-color: var(--primary);
  }

  /* Animation keyframes */
  @keyframes slideUp {
    from {
      transform: translateY(20px);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }

  @keyframes fadeIn {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }

  @keyframes pulseSoft {
    0%, 100% {
      opacity: 1;
    }
    50% {
      opacity: 0.7;
    }
  }

  .animate-slide-up {
    animation: slideUp 0.3s ease-out;
  }

  .animate-fade-in {
    animation: fadeIn 0.2s ease-out;
  }

  .animate-pulse-soft {
    animation: pulseSoft 2s infinite;
  }

  /* Additional splash screen animations */
  @keyframes floatUp {
    from {
      transform: translateY(30px);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }

  @keyframes scaleIn {
    from {
      transform: scale(0.5);
      opacity: 0;
    }
    to {
      transform: scale(1);
      opacity: 1;
    }
  }

  @keyframes shimmerGlow {
    0% {
      box-shadow: 0 0 20px rgba(59, 130, 246, 0.3);
    }
    50% {
      box-shadow: 0 0 40px rgba(34, 197, 94, 0.5);
    }
    100% {
      box-shadow: 0 0 20px rgba(59, 130, 246, 0.3);
    }
  }

  .animate-float-up {
    animation: floatUp 0.8s ease-out;
  }

  .animate-scale-in {
    animation: scaleIn 0.6s ease-out;
  }

  .animate-shimmer-glow {
    animation: shimmerGlow 2s infinite;
  }

  /* Mobile keyboard viewport handling */
  .mobile-input-container {
    /* Use dvh (dynamic viewport height) for mobile keyboards */
    min-height: fit-content;
    position: relative;
    z-index: 1000;
  }

  .mobile-form {
    /* Ensure form stays visible when keyboard appears */
    position: relative;
    width: 100%;
  }

  .mobile-input {
    /* Optimize input for mobile keyboards */
    touch-action: manipulation;
    -webkit-user-select: text;
    user-select: text;
    /* Prevent iOS zoom on input focus */
    font-size: 16px !important;
  }

  .mobile-button {
    /* Ensure buttons remain accessible with keyboard */
    touch-action: manipulation;
    min-height: 44px; /* iOS recommended touch target */
  }

  /* iOS specific keyboard handling */
  @supports (-webkit-touch-callout: none) {
    .mobile-input-container {
      /* Handle iOS virtual keyboard with environment variables */
      padding-bottom: env(keyboard-inset-height, 0px);
      /* Use safe area insets for iPhone notch/home indicator */
      padding-bottom: max(env(keyboard-inset-height, 0px), env(safe-area-inset-bottom, 0px));
    }

    .mobile-input:focus {
      /* Prevent iOS zoom on focus */
      transform: translateZ(0);
      -webkit-transform: translateZ(0);
    }
  }

  /* Viewport meta tag support for keyboard handling */
  @media screen and (max-height: 500px) {
    /* When keyboard is likely open (reduced viewport height) */
    .mobile-input-container {
      /* Move container higher when keyboard is open */
      position: fixed;
      top: 20px;
      left: 50%;
      transform: translateX(-50%);
      width: calc(100% - 40px);
      max-width: 384px;
      z-index: 9999;
      background: rgba(255, 255, 255, 0.95);
      backdrop-filter: blur(10px);
      border-radius: 12px;
      padding: 20px;
      box-shadow: 0 10px 25px rgba(0, 0, 0, 0.15);
    }

    .dark .mobile-input-container {
      background: rgba(17, 24, 39, 0.95);
    }
  }

  /* Very aggressive positioning for very small screens */
  @media screen and (max-height: 400px) {
    .mobile-input-container {
      top: 10px;
      padding: 15px;
    }
  }

  /* Smooth transitions for keyboard appearance */
  .mobile-form {
    transition: all 0.3s ease-in-out;
  }

  /* Ensure content stays visible on very small screens */
  @media screen and (max-height: 400px) {
    .mobile-input-container {
      padding: 10px 0;
    }

    .mobile-input-container .space-y-3 > * + * {
      margin-top: 0.5rem;
    }
  }

  /* Keyboard open state styling */
  .mobile-input-container.keyboard-open {
    position: fixed !important;
    top: 20px !important;
    left: 50% !important;
    transform: translateX(-50%) !important;
    width: calc(100% - 40px) !important;
    max-width: 384px !important;
    z-index: 9999 !important;
    background: rgba(255, 255, 255, 0.98) !important;
    backdrop-filter: blur(15px) !important;
    border-radius: 16px !important;
    padding: 24px !important;
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.2) !important;
    border: 1px solid rgba(255, 255, 255, 0.2) !important;
    transition: all 0.3s ease-in-out !important;
  }

  .dark .mobile-input-container.keyboard-open {
    background: rgba(17, 24, 39, 0.98) !important;
    border: 1px solid rgba(75, 85, 99, 0.3) !important;
  }

  /* Ensure input text is always visible in mobile keyboard mode */
  .mobile-input-container.keyboard-open .mobile-input {
    color: #1f2937 !important;
    background-color: #ffffff !important;
    border-color: #3b82f6 !important;
    font-size: 16px !important;
    font-weight: 500 !important;
  }

  .dark .mobile-input-container.keyboard-open .mobile-input {
    color: #f9fafb !important;
    background-color: #374151 !important;
    border-color: #60a5fa !important;
  }

  /* Force input visibility regardless of other styles */
  .mobile-input-container .mobile-input {
    color: #000000 !important;
    background-color: #ffffff !important;
    -webkit-text-fill-color: #000000 !important;
    -webkit-appearance: none !important;
    border: 2px solid #3b82f6 !important;
    font-weight: 600 !important;
    text-align: center !important;
  }

  .mobile-input-container .mobile-input:focus {
    color: #000000 !important;
    background-color: #ffffff !important;
    -webkit-text-fill-color: #000000 !important;
    outline: none !important;
    box-shadow: 0 0 0 2px rgba(59, 130, 246, 0.5) !important;
    border: 2px solid #3b82f6 !important;
  }

  .dark .mobile-input-container .mobile-input {
    color: #ffffff !important;
    background-color: #374151 !important;
    -webkit-text-fill-color: #ffffff !important;
    border: 2px solid #60a5fa !important;
  }

  .dark .mobile-input-container .mobile-input:focus {
    color: #ffffff !important;
    background-color: #374151 !important;
    -webkit-text-fill-color: #ffffff !important;
    border: 2px solid #60a5fa !important;
  }

  /* Native HTML input overrides for complete visibility control */
  input[type="tel"], input[type="text"] {
    color: #000000 !important;
    background-color: #ffffff !important;
    -webkit-text-fill-color: #000000 !important;
    -webkit-text-security: none !important;
    -webkit-appearance: none !important;
    font-size: 18px !important;
    font-weight: 700 !important;
    text-align: center !important;
    letter-spacing: 2px !important;
  }

  .mobile-input-container input[type="tel"], 
  .mobile-input-container input[type="text"] {
    color: #000000 !important;
    background-color: #ffffff !important;
    -webkit-text-fill-color: #000000 !important;
    -webkit-text-security: none !important;
    -webkit-appearance: none !important;
    font-size: 18px !important;
    font-weight: 700 !important;
    text-align: center !important;
    letter-spacing: 2px !important;
    border: 3px solid #1d4ed8 !important;
    border-radius: 8px !important;
    outline: none !important;
    box-shadow: none !important;
  }

