import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { ArrowUp, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import Header from "@/components/header";
import CategoryFilter from "@/components/category-filter";
import NewsCard from "@/components/news-card";
import BottomNavigation from "@/components/bottom-navigation";
import type { Article } from "@shared/schema";

export default function Home() {
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [activeTab, setActiveTab] = useState('home');
  const [showScrollTop, setShowScrollTop] = useState(false);
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Fetch articles based on selected category
  const {
    data: articles = [],
    isLoading,
    error,
    refetch
  } = useQuery<Article[]>({
    queryKey: ['/api/articles', selectedCategory],
    queryFn: async () => {
      const url = selectedCategory !== 'all' ? `/api/articles?category=${selectedCategory}` : '/api/articles';
      const response = await fetch(url, {
        credentials: 'include',
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(errorText || 'Failed to fetch articles');
      }

      const data = await response.json();
      console.log('Fetched articles:', data); // Debug log
      return data;
    },
  });

  // Refresh articles mutation
  const refreshMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest('POST', '/api/articles/refresh');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/articles'] });
      toast({
        title: "Success",
        description: "Articles refreshed successfully!",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to refresh articles",
        variant: "destructive",
      });
    },
  });

  // Handle scroll events for showing/hiding scroll to top button
  useEffect(() => {
    const handleScroll = () => {
      setShowScrollTop(window.scrollY > 300);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleRefresh = () => {
    refreshMutation.mutate();
  };

  const handleCategoryChange = (category: string) => {
    setSelectedCategory(category);
  };

  const handleArticleClick = (article: Article) => {
    // TODO: Open article detail modal or navigate to detail page
    console.log('Opening article:', article.title);
  };

  const handleShare = (e: React.MouseEvent, article: Article) => {
    e.stopPropagation();

    if (navigator.share) {
      navigator.share({
        title: article.title,
        text: article.content,
        url: window.location.href,
      }).catch(console.error);
    } else {
      // Fallback for browsers without native share
      navigator.clipboard.writeText(`${article.title}\n\n${article.content}\n\nSource: ${article.source}`);
      toast({
        title: "Copied to clipboard",
        description: "Article content copied to clipboard",
      });
    }
  };

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLoadMore = () => {
    // TODO: Implement pagination
    console.log('Loading more articles...');
  };

  if (error) {
    return (
      <div className="min-h-screen bg-neutral-50 dark:bg-neutral-900">
        <Header onRefresh={handleRefresh} isRefreshing={refreshMutation.isPending} />
        <div className="flex items-center justify-center min-h-[60vh]">
          <div className="text-center p-6">
            <div className="w-16 h-16 bg-danger/10 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-danger" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L3.08 16.5c-.77.833.192 2.5 1.732 2.5z" />
              </svg>
            </div>
            <h2 className="text-xl font-semibold text-neutral-800 dark:text-white mb-2">
              Failed to Load Articles
            </h2>
            <p className="text-neutral-600 dark:text-neutral-400 mb-4">
              {error instanceof Error ? error.message : 'Please check your Google Sheets integration settings.'}
            </p>
            <Button onClick={handleRefresh} disabled={refreshMutation.isPending}>
              {refreshMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Try Again
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // Debug log
  console.log('Articles data:', articles, 'Loading:', isLoading, 'Error:', error);

  return (
    <div className="h-screen flex flex-col bg-gray-50 dark:bg-neutral-950">
      {/* Fixed Header */}
      <div className="flex-shrink-0">
        <Header onRefresh={handleRefresh} isRefreshing={refreshMutation.isPending} />
        <CategoryFilter 
          selectedCategory={selectedCategory}
          onCategoryChange={handleCategoryChange}
        />
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden">
        {isLoading ? (
          // Loading State
          <div className="h-full flex items-center justify-center">
            <div className="text-center">
              <Loader2 className="h-8 w-8 animate-spin mx-auto mb-4 text-primary" />
              <p className="text-neutral-600 dark:text-neutral-400">Loading articles...</p>
            </div>
          </div>
        ) : articles.length === 0 ? (
          // Empty State
          <div className="flex items-center justify-center min-h-[60vh]">
            <div className="text-center p-6">
              <div className="w-16 h-16 bg-neutral-100 dark:bg-neutral-800 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8 text-neutral-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" />
                </svg>
              </div>
              <h2 className="text-xl font-semibold text-neutral-800 dark:text-white mb-2">
                No Articles Found
              </h2>
              <p className="text-neutral-600 dark:text-neutral-400 mb-4">
                {selectedCategory === 'all' 
                  ? 'No articles are available at the moment.'
                  : `No articles found for the ${selectedCategory} category.`
                }
              </p>
              <Button onClick={handleRefresh} variant="outline">
                Refresh Articles
              </Button>
            </div>
          </div>
        ) : (
          // News Cards - Inshorts style full-screen layout
          <div className="h-full overflow-y-auto snap-y snap-mandatory">
            {articles.map((article) => (
              <NewsCard
                key={article.id}
                article={article}
                onClick={() => handleArticleClick(article)}
                onShare={(e) => handleShare(e, article)}
              />
            ))}
          </div>
        )}
      </div>

      {/* Fixed Bottom Navigation */}
      <div className="flex-shrink-0">
        <BottomNavigation activeTab="home" onTabChange={() => {}} />
      </div>
    </div>
  );
}

stocksshorts-backup/server/services/scre.content:
import axios from 'axios';

interface ScreenerStockData {
  symbol: string;
  name: string;
  currentPrice: number;
  change: number;
  changePercent: number;
  marketCap: number;
  pe: number;
  pb: number;
  roe: number;
  debtToEquity: number;
  sector: string;
  industry: string;
  dayHigh: number;
  dayLow: number;
  volume: number;
}

interface ScreenerSearchResult {
  id: number;
  name: string;
  url: string;
}

export class ScreenerService {
  private baseUrl = 'https://www.screener.in/api';
  private headers = {
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
    'Accept': 'application/json',
    'Referer': 'https://www.screener.in/',
    'X-Requested-With': 'XMLHttpRequest',
  };

  async searchStock(query: string): Promise<ScreenerSearchResult[]> {
    try {
      const response = await axios.get(`${this.baseUrl}/company/search/`, {
        params: { q: query.trim() },
        headers: this.headers,
        timeout: 5000,
      });

      return response.data || [];
    } catch (error) {
      console.error(`Error searching stock ${query}:`, error);
      return [];
    }
  }

  async getStockData(stockId: number): Promise<ScreenerStockData | null> {
    try {
      const response = await axios.get(`${this.baseUrl}/company/${stockId}/`, {
        headers: this.headers,
        timeout: 5000,
      });

      const data = response.data;
      if (!data) return null;

      return {
        symbol: data.bse_code || data.nse_code || '',
        name: data.name || '',
        currentPrice: data.current_price || 0,
        change: data.change || 0,
        changePercent: data.change_percent || 0,
        marketCap: data.market_cap || 0,
        pe: data.pe || 0,
        pb: data.pb || 0,
        roe: data.roe || 0,
        debtToEquity: data.debt_to_equity || 0,
        sector: data.sector || '',
        industry: data.industry || '',
        dayHigh: data.day_high || 0,
        dayLow: data.day_low || 0,
        volume: data.volume || 0,
      };
    } catch (error) {
      console.error(`Error fetching stock data for ID ${stockId}:`, error);
      return null;
    }
  }

  async getStockByName(stockName: string): Promise<ScreenerStockData | null> {
    try {
      const searchResults = await this.searchStock(stockName);
      if (searchResults.length === 0) return null;

      // Take the first (most relevant) result
      const stockData = await this.getStockData(searchResults[0].id);
      return stockData;
    } catch (error) {
      console.error(`Error getting stock data for ${stockName}:`, error);
      return null;
    }
  }

  async getMultipleStocks(stockNames: string[]): Promise<{ [key: string]: ScreenerStockData }> {
    const results: { [key: string]: ScreenerStockData } = {};

    for (const stockName of stockNames) {
      const data = await this.getStockByName(stockName);
      if (data) {
        results[stockName.toLowerCase()] = data;
      }
      // Add delay to avoid rate limiting
      await new Promise(resolve => setTimeout(resolve, 1000));
    }

    return results;
  }

  // Get top performers from popular stocks
  async getTopPerformers(): Promise<ScreenerStockData[]> {
    const popularStocks = [
      'Reliance Industries', 'TCS', 'HDFC Bank', 'Infosys', 
      'ICICI Bank', 'Bharti Airtel', 'State Bank of India',
      'ITC', 'Hindustan Unilever', 'Kotak Mahindra Bank'
    ];

    const results: ScreenerStockData[] = [];

    for (const stock of popularStocks) {
      const data = await this.getStockByName(stock);
      if (data && data.changePercent > 0) {
        results.push(data);
      }
      await new Promise(resolve => setTimeout(resolve, 500));
    }

    return results.sort((a, b) => b.changePercent - a.changePercent).slice(0, 5);
  }
}

export const screenerService = new ScreenerService();

