                      onClick={() => advisor.phone && window.open(`https://wa.me/91${advisor.phone?.replace(/\D/g, '')}`, '_blank')}
                      disabled={!advisor.phone}
                    >
                      <svg className="h-3 w-3 mr-1" viewBox="0 0 24 24" fill="currentColor">
