        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
          'Accept': 'application/json',
          'Referer': `https://www.screener.in/company/${companyId}/`
        }
      });

      if (response.ok) {
        const quarterlyData = await response.json();
        return quarterlyData;
      }

      return null;
    } catch (error) {
      return null;
