  ContextMenuRadioGroup,
}

stocksshorts-backup/shared/schema.ts.content:
import { pgTable, text, serial, integer, timestamp, varchar, index, jsonb, boolean } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// Session storage table for authentication
export const sessions = pgTable(
  "sessions",
  {
    sid: varchar("sid").primaryKey(),
    sess: jsonb("sess").notNull(),
    expire: timestamp("expire").notNull(),
  },
  (table) => [index("IDX_session_expire").on(table.expire)],
);

// User storage table for mobile authentication
export const users = pgTable("users", {
  id: serial("id").primaryKey(),
  phoneNumber: varchar("phone_number").unique().notNull(),
  firstName: varchar("first_name"),
  lastName: varchar("last_name"),
  age: integer("age"),
  gender: varchar("gender"),
  city: varchar("city"),
  occupation: varchar("occupation"),
  investmentExperience: varchar("investment_experience"),
  isVerified: varchar("is_verified").default("false"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

// OTP verification table
export const otpVerifications = pgTable("otp_verifications", {
  id: serial("id").primaryKey(),
  phoneNumber: varchar("phone_number").notNull(),
  otp: varchar("otp").notNull(),
  expiresAt: timestamp("expires_at").notNull(),
  isUsed: varchar("is_used").default("false"),
  createdAt: timestamp("created_at").defaultNow(),
});

// AI query tracking for daily limits
export const aiQueries = pgTable("ai_queries", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  query: text("query").notNull(),
  response: text("response"),
  createdAt: timestamp("created_at").defaultNow(),
});

export const articles = pgTable("articles", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  content: text("content").notNull(),
  type: text("type").notNull(), // Index, Warrants, StocksShorts Special, Breakout Stocks, Educational, IPO, Global, Most Active, Order Win
  time: timestamp("time"), // Allow null for articles without specific timestamp
  source: text("source").notNull(),
  sentiment: text("sentiment").notNull(), // Positive, Negative, Neutral
  priority: text("priority").notNull(), // High, Medium, Low
  imageUrl: text("image_url"), // URL for article image
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const insertUserSchema = createInsertSchema(users).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
});

export const insertOtpSchema = createInsertSchema(otpVerifications).omit({
  id: true,
  createdAt: true,
});

export const insertArticleSchema = createInsertSchema(articles).omit({
  id: true,
  createdAt: true,
});

export type InsertUser = z.infer<typeof insertUserSchema>;
export type User = typeof users.$inferSelect;
export type InsertOtp = z.infer<typeof insertOtpSchema>;
export type OtpVerification = typeof otpVerifications.$inferSelect;

export const insertAiQuerySchema = createInsertSchema(aiQueries).omit({
  id: true,
  createdAt: true,
});

export type InsertAiQuery = z.infer<typeof insertAiQuerySchema>;
export type AiQuery = typeof aiQueries.$inferSelect;
export type InsertArticle = z.infer<typeof insertArticleSchema>;
export type Article = typeof articles.$inferSelect;

// AI Articles table - separate from Google Sheets articles
export const aiArticles = pgTable("ai_articles", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  content: text("content").notNull(),
  type: text("type").default("AI News"),
  source: text("source").default("AI Generated"),
  sentiment: text("sentiment").default("Neutral"),
  priority: text("priority").default("Medium"),
  imageUrl: text("image_url"),
  newsDate: timestamp("news_date").notNull(), // Date when the news actually happened
  createdAt: timestamp("created_at").defaultNow(),
});

export const insertAiArticleSchema = createInsertSchema(aiArticles).omit({
  id: true,
  createdAt: true,
});

export type InsertAiArticle = z.infer<typeof insertAiArticleSchema>;
export type AiArticle = typeof aiArticles.$inferSelect;

// AI Article Reports table for flagging system
export const aiArticleReports = pgTable("ai_article_reports", {
  id: serial("id").primaryKey(),
  articleId: integer("article_id").notNull().references(() => aiArticles.id),
  reportedAt: timestamp("reported_at").defaultNow().notNull(),
  status: varchar("status", { length: 50 }).default("pending").notNull(), // pending, reviewed, dismissed, removed
  reviewedAt: timestamp("reviewed_at"),
  reviewedBy: varchar("reviewed_by", { length: 100 }),
  reviewNotes: text("review_notes"),
});

export const insertAiArticleReportSchema = createInsertSchema(aiArticleReports).omit({
  id: true,
  reportedAt: true,
});

export type InsertAiArticleReport = z.infer<typeof insertAiArticleReportSchema>;
export type AiArticleReport = typeof aiArticleReports.$inferSelect;

// Investment Advisor table
export const investmentAdvisors = pgTable("investment_advisors", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  company: text("company").default(''),
  designation: text("designation").default(''),
  phone: text("phone").notNull(),
  email: text("email").notNull(),
  website: text("website").default(''),
  specialization: text("specialization").default(''),
  experience: text("experience").default(''),
  location: text("location").default(''),
  rating: text("rating").default('4.0'),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const insertInvestmentAdvisorSchema = createInsertSchema(investmentAdvisors).omit({
  id: true,
  createdAt: true,
});

export type InsertInvestmentAdvisor = z.infer<typeof insertInvestmentAdvisorSchema>;
export type InvestmentAdvisor = typeof investmentAdvisors.$inferSelect;

// Google Sheets row structure
export interface GoogleSheetsRow {
  ID: string;
  Title: string;
  Content: string;
  Type: string;
  Time: string;
  Source: string;
  Sentiment: string;
  Priority: string;
  ImageURL: string;
  Category: string;
}

// Investment Advisor Google Sheets row structure
export interface InvestmentAdvisorRow {
  Name: string;
  Company: string;
  Designation: string;
  Phone: string;
  Email: string;
  Website: string;
  Specialization: string;
  Experience: string;
  Location: string;
  Rating: string;
}

// Gmail tracking and personalized articles
export const gmailCredentials = pgTable("gmail_credentials", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  accessToken: text("access_token").notNull(),
  refreshToken: text("refresh_token"),
  expiryDate: timestamp("expiry_date"),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const emailInsights = pgTable("email_insights", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  companies: text("companies").array(),
  sectors: text("sectors").array(),
  keywords: text("keywords").array(),
  topics: text("topics").array(),
  sentiment: text("sentiment").notNull(),
  scanDate: timestamp("scan_date").defaultNow(),
  emailCount: integer("email_count").default(0),
});

export const personalizedArticles = pgTable("personalized_articles", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  title: text("title").notNull(),
  content: text("content").notNull(),
  source: text("source").notNull(),
  type: text("type").notNull().default("Personalized News"),
  sentiment: text("sentiment").notNull(),
  priority: text("priority").notNull(),
  newsDate: timestamp("news_date").notNull(),
  personalizationReason: text("personalization_reason").notNull(),
  createdAt: timestamp("created_at").defaultNow(),
});

export const insertGmailCredentialsSchema = createInsertSchema(gmailCredentials).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
});

export const insertEmailInsightsSchema = createInsertSchema(emailInsights).omit({
  id: true,
  scanDate: true,
});

export const insertPersonalizedArticleSchema = createInsertSchema(personalizedArticles).omit({
  id: true,
  createdAt: true,
});

export type InsertGmailCredentials = z.infer<typeof insertGmailCredentialsSchema>;
export type GmailCredentials = typeof gmailCredentials.$inferSelect;
export type InsertEmailInsights = z.infer<typeof insertEmailInsightsSchema>;
export type EmailInsights = typeof emailInsights.$inferSelect;
export type InsertPersonalizedArticle = z.infer<typeof insertPersonalizedArticleSchema>;
export type PersonalizedArticle = typeof personalizedArticles.$inferSelect;

// Comments system for Trader View articles
export const comments = pgTable("comments", {
  id: serial("id").primaryKey(),
  articleId: integer("article_id").notNull(),
  userId: integer("user_id").notNull(),
  parentId: integer("parent_id"), // For replies
  content: text("content").notNull(),
  authorName: varchar("author_name", { length: 100 }),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const insertCommentSchema = createInsertSchema(comments).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
});

export type InsertComment = z.infer<typeof insertCommentSchema>;
export type Comment = typeof comments.$inferSelect;

client/src/hooks/useAuth.ts.content:
import { useQuery } from "@tanstack/react-query";

export function useAuth() {
  const { data: user, isLoading, error } = useQuery({
    queryKey: ["/api/auth/user"],
    retry: false,
    staleTime: 5 * 60 * 1000, // 5 minutes
    gcTime: 10 * 60 * 1000, // 10 minutes
  });

  return {
    user,
    isLoading,
    isAuthenticated: !!user,
    error,
  };
}

stocksshorts-backup/client/src/pages/Gma.content:
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Mail, Eye, TrendingUp, Shield, Zap, AlertCircle } from "@/lib/icons";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";

export default function GmailConnect() {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isConnected, setIsConnected] = useState(false);
  const [personalizedArticles, setPersonalizedArticles] = useState<any[]>([]);
  const { toast } = useToast();

  const handleConnectGmail = async () => {
    setIsConnecting(true);
    try {
      // Get Gmail auth URL
      const data = await apiRequest("GET", "/api/gmail/auth-url");
      const { authUrl } = data;

      // Open Gmail authorization in new window
      const popup = window.open(authUrl, 'gmail-auth', 'width=500,height=600');

      // Listen for authorization completion
      const checkClosed = setInterval(() => {
        if (popup?.closed) {
          clearInterval(checkClosed);
          setIsConnecting(false);

          // Simulate successful connection for demo
          setIsConnected(true);
          toast({
            title: "Gmail Connected!",
            description: "Your email is now being tracked for personalized articles.",
          });
        }
      }, 1000);

    } catch (error) {
      console.error('Gmail connection error:', error);
      setIsConnecting(false);
      toast({
        title: "Connection Failed",
        description: "Unable to connect Gmail. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleScanEmails = async () => {
    setIsScanning(true);
    try {
      await apiRequest("POST", "/api/gmail/scan");

      // Fetch personalized articles
      const articles = await apiRequest("GET", "/api/personalized-articles?limit=5");
      setPersonalizedArticles(Array.isArray(articles) ? articles : []);

      toast({
        title: "Email Scan Complete",
        description: `Generated ${Array.isArray(articles) ? articles.length : 0} personalized articles based on your interests.`,
      });
    } catch (error) {
      console.error('Email scanning error:', error);
      toast({
        title: "Scan Failed",
        description: "Unable to scan emails. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-gray-900 dark:to-gray-800 p-4">
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="text-center">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
            Personalized Market Intelligence
          </h1>
          <p className="text-gray-600 dark:text-gray-300">
            Connect your Gmail to generate personalized stock market articles based on your interests
          </p>
        </div>

        {/* How it Works */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Eye className="h-5 w-5 text-blue-600" />
              How Gmail Tracking Works
            </CardTitle>
            <CardDescription>
              Our AI analyzes your email patterns to create personalized market content
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid md:grid-cols-3 gap-4">
              <div className="flex items-start gap-3">
                <div className="bg-blue-100 dark:bg-blue-900 p-2 rounded-lg">
                  <Mail className="h-4 w-4 text-blue-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-sm">Email Analysis</h3>
                  <p className="text-xs text-gray-600 dark:text-gray-400">
                    Scans last 7 days for company mentions, financial newsletters, research reports
                  </p>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <div className="bg-green-100 dark:bg-green-900 p-2 rounded-lg">
                  <TrendingUp className="h-4 w-4 text-green-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-sm">Interest Mapping</h3>
                  <p className="text-xs text-gray-600 dark:text-gray-400">
                    Identifies your preferred sectors, companies, and investment themes
                  </p>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <div className="bg-purple-100 dark:bg-purple-900 p-2 rounded-lg">
                  <Zap className="h-4 w-4 text-purple-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-sm">Smart Generation</h3>
                  <p className="text-xs text-gray-600 dark:text-gray-400">
                    Creates relevant corporate announcements matching your interests
                  </p>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Privacy & Security */}
        <Card className="border-amber-200 bg-amber-50 dark:bg-amber-900/20">
          <CardContent className="pt-6">
            <div className="flex items-start gap-3">
              <Shield className="h-5 w-5 text-amber-600 mt-0.5" />
              <div>
                <h3 className="font-semibold text-amber-900 dark:text-amber-200">
                  Privacy & Security
                </h3>
                <p className="text-sm text-amber-800 dark:text-amber-300 mt-1">
                  We only read email metadata and content for analysis. No emails are stored. 
                  All data is encrypted and used solely for generating personalized market content.
                </p>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Connection Status */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Mail className="h-5 w-5" />
              Gmail Connection
              {isConnected && <Badge variant="default" className="bg-green-600">Connected</Badge>}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {!isConnected ? (
              <div className="text-center py-8">
                <Mail className="h-12 w-12 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-semibold mb-2">Connect Your Gmail</h3>
                <p className="text-gray-600 dark:text-gray-400 mb-6">
                  Authorize StocksShorts to analyze your email for personalized market insights
                </p>
                <Button 
                  onClick={handleConnectGmail}
                  disabled={isConnecting}
                  className="bg-blue-600 hover:bg-blue-700"
                  size="lg"
                >
                  {isConnecting ? "Connecting..." : "Connect Gmail"}
                </Button>
              </div>
            ) : (
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="font-semibold text-green-600">Gmail Connected Successfully</h3>
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                      Ready to scan your emails for market interests
                    </p>
                  </div>
                  <Badge variant="default" className="bg-green-600">Active</Badge>
                </div>

                <Separator />

                <Button 
                  onClick={handleScanEmails}
                  disabled={isScanning}
                  className="w-full"
                  variant="outline"
                >
                  {isScanning ? "Scanning Emails..." : "Scan Emails & Generate Articles"}
                </Button>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Personalized Articles */}
        {personalizedArticles.length > 0 && (
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <TrendingUp className="h-5 w-5 text-purple-600" />
                Your Personalized Articles
              </CardTitle>
              <CardDescription>
                Generated based on your email interests and market activity
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              {personalizedArticles.map((article, index) => (
                <div key={index} className="border rounded-lg p-4 space-y-2">
                  <div className="flex items-start justify-between">
                    <h3 className="font-semibold text-sm">{article.title}</h3>
                    <Badge variant="outline" className="text-xs">
                      {article.priority === "1" ? "High" : article.priority === "2" ? "Medium" : "Low"} Priority
                    </Badge>
                  </div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 line-clamp-2">
                    {article.content}
                  </p>
                  <div className="flex items-center justify-between text-xs text-gray-500">
                    <span>{article.source}</span>
                    <span className="bg-blue-100 dark:bg-blue-900 px-2 py-1 rounded">
                      {article.personalizationReason}
                    </span>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        )}

        {/* Setup Instructions */}
        {!isConnected && (
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <AlertCircle className="h-5 w-5 text-blue-600" />
                Setup Instructions
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3 text-sm">
                <div className="flex items-start gap-2">
                  <div className="bg-blue-600 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs font-bold">1</div>
                  <p>Click "Connect Gmail" to authorize StocksShorts access</p>
                </div>
                <div className="flex items-start gap-2">
                  <div className="bg-blue-600 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs font-bold">2</div>
                  <p>Sign in with your dedicated Gmail account for market research</p>
                </div>
                <div className="flex items-start gap-2">
                  <div className="bg-blue-600 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs font-bold">3</div>
                  <p>Grant read-only access to your email content</p>
                </div>
                <div className="flex items-start gap-2">
                  <div className="bg-blue-600 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs font-bold">4</div>
                  <p>Scan emails to generate personalized market articles</p>
                </div>
              </div>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}

