import { Request, Response, NextFunction } from "express";
import { storage } from "./storage";

// Generate 6-digit OTP
function generateOTP(): string {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

// Validate Indian mobile number format
function isValidIndianMobile(phoneNumber: string): boolean {
  const indianMobileRegex = /^(\+91)?[6-9]\d{9}$/;
  return indianMobileRegex.test(phoneNumber.replace(/\s/g, ''));
}

// Normalize phone number to standard format
function normalizePhoneNumber(phoneNumber: string): string {
  let normalized = phoneNumber.replace(/\s/g, '');
  if (normalized.startsWith('+91')) {
    normalized = normalized.substring(3);
  }
  return normalized;
}

// Send OTP via SMS using Fast2SMS (₹0.15 per SMS) - now activated and working
async function sendSMS(phoneNumber: string, otp: string): Promise<boolean> {
  try {
    const fast2smsKey = process.env.FAST2SMS_API_KEY;
    console.log(`Environment check - Fast2SMS key present: ${!!fast2smsKey}`);

    // Try Fast2SMS first - now activated with balance
    if (fast2smsKey) {
      try {
        console.log(`Sending OTP to ${phoneNumber} via Fast2SMS (₹0.15 per SMS)`);
        console.log(`OTP being sent: ${otp}`);

        const fast2smsResponse = await fetch('https://www.fast2sms.com/dev/bulkV2', {
          method: 'POST',
          headers: { 
            'Authorization': fast2smsKey,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            message: `${otp} is your StocksShorts OTP. Valid for 5 minutes. Do not share this code.`,
            language: 'english',
            route: 'q',
            numbers: phoneNumber
          })
        });

        const fast2smsResult = await fast2smsResponse.json();
        console.log(`Fast2SMS full response:`, JSON.stringify(fast2smsResult, null, 2));

        if (fast2smsResult.return === true) {
          console.log(`✅ SMS sent successfully to ${phoneNumber} via Fast2SMS (Request ID: ${fast2smsResult.request_id})`);
          return true;
        } else {
          console.log(`❌ Fast2SMS failed: ${fast2smsResult.message}`);
        }
      } catch (fast2smsError) {
        console.log(`Fast2SMS error:`, fast2smsError);
      }
    }

    // Fallback to MSG91 if Fast2SMS fails
    try {
      console.log(`Fallback: Sending via MSG91 demo`);

      const msg91Response = await fetch(`https://control.msg91.com/api/sendotp.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          authkey: 'demo',
          mobile: `91${phoneNumber}`,
          message: `${otp} is your StocksShorts verification code. Valid for 5 minutes.`,
          sender: 'VERIFY',
          otp: otp
        })
      });

      const msg91Text = await msg91Response.text();
      console.log(`MSG91 fallback response:`, msg91Text);

      if (msg91Text.includes('success')) {
        console.log(`MSG91 fallback responded for ${phoneNumber}`);
      }
    } catch (msg91Error) {
      console.log(`MSG91 fallback error:`, msg91Error);
    }

    // Console display for testing
    console.log(`\n🔑 YOUR OTP CODE: ${otp}`);
    console.log(`📱 Phone: ${phoneNumber} | ⏰ Valid for 5 minutes`);
    console.log(`💡 For real SMS delivery:`);
    console.log(`   • Fast2SMS: ₹0.15/SMS (activated)`);
    console.log(`   • MSG91: ₹0.15/SMS (register at msg91.com)`);
    console.log(`   • Twilio: ₹8.3/SMS (premium reliability)\n`);
    return true;

  } catch (error) {
    console.error('SMS delivery error:', error);
    console.log(`\n🔑 YOUR OTP CODE: ${otp}`);
    console.log(`📱 Phone: ${phoneNumber} | ⏰ Valid for 5 minutes\n`);
    return true;
  }
}

export const mobileAuth = {
  // Send OTP to mobile number
  sendOTP: async (req: Request, res: Response) => {
    try {
      const { phoneNumber } = req.body;

      if (!phoneNumber) {
        return res.status(400).json({ message: "Phone number is required" });
      }

      const normalizedPhone = normalizePhoneNumber(phoneNumber);

      if (!isValidIndianMobile(normalizedPhone)) {
        return res.status(400).json({ message: "Invalid Indian mobile number" });
      }

      const otp = generateOTP();
      const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 minutes from now

      // Store OTP in database
      await storage.createOtp({
        phoneNumber: normalizedPhone,
        otp,
        expiresAt,
        isUsed: "false"
      });

      // Send SMS
      await sendSMS(normalizedPhone, otp);

      res.json({ 
        message: "OTP sent successfully", 
        phoneNumber: normalizedPhone 
      });
    } catch (error) {
      console.error("Send OTP error:", error);
      res.status(500).json({ message: "Failed to send OTP" });
    }
  },

  // Verify OTP and login/register user
  verifyOTP: async (req: Request, res: Response) => {
    try {
      const { phoneNumber, otp } = req.body;

      if (!phoneNumber || !otp) {
        return res.status(400).json({ message: "Phone number and OTP are required" });
      }

      const normalizedPhone = normalizePhoneNumber(phoneNumber);

      // Verify OTP
      const validOtp = await storage.getValidOtp(normalizedPhone, otp);
      if (!validOtp) {
        return res.status(400).json({ message: "Invalid or expired OTP" });
      }

      // Mark OTP as used
      await storage.markOtpAsUsed(validOtp.id);

      // Check if user exists, if not create new user
      let user = await storage.getUserByPhone(normalizedPhone);
      if (!user) {
        user = await storage.createUser({
          phoneNumber: normalizedPhone,
          isVerified: "true"
        });
      } else {
        // Verify existing user
        await storage.verifyUser(normalizedPhone);
      }

      // Set session with proper user object
      (req.session as any).user = {
        id: user.id,
        phoneNumber: user.phoneNumber,
        firstName: user.firstName,
        lastName: user.lastName,
        isVerified: user.isVerified
      };
      (req.session as any).userId = user.id;
      (req.session as any).phoneNumber = user.phoneNumber;

      res.json({ 
        message: "Login successful", 
        user: {
          id: user.id,
          phoneNumber: user.phoneNumber,
          firstName: user.firstName,
          lastName: user.lastName,
          isVerified: user.isVerified
        }
      });
    } catch (error) {
      console.error("Verify OTP error:", error);
      res.status(500).json({ message: "Failed to verify OTP" });
    }
  },

  // Check if user is authenticated
  isAuthenticated: (req: Request, res: Response, next: NextFunction) => {
    const session = req.session as any;
    if (session && session.user && session.userId) {
      next();
    } else {
      res.status(401).json({ message: "Unauthorized" });
    }
  },

  // Get current authenticated user
  getCurrentUser: async (req: Request, res: Response) => {
    try {
      const session = req.session as any;
      if (!session || !session.userId) {
        return res.status(401).json({ message: "Unauthorized" });
      }

      const user = await storage.getUser(session.userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }

      res.json({
        id: user.id,
        phoneNumber: user.phoneNumber,
        firstName: user.firstName,
        lastName: user.lastName,
        age: user.age,
        gender: user.gender,
        city: user.city,
        occupation: user.occupation,
        investmentExperience: user.investmentExperience,
        isVerified: user.isVerified
      });
    } catch (error) {
      console.error("Get current user error:", error);
      res.status(500).json({ message: "Failed to get user" });
    }
  },

  // Logout user
  logout: (req: Request, res: Response) => {
    req.session.destroy((err) => {
      if (err) {
        console.error("Logout error:", err);
        return res.status(500).json({ message: "Failed to logout" });
      }
      res.json({ message: "Logged out successfully" });
    });
  },

  // Update user profile
  updateProfile: async (req: Request, res: Response) => {
    try {
      const session = req.session as any;
      if (!session || !session.userId) {
        return res.status(401).json({ message: "Unauthorized" });
      }

      const { firstName, lastName } = req.body;
      const user = await storage.getUser(session.userId);

      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }

      // Update user with new information
      const updatedUser = await storage.upsertUser({
        id: user.id,
        phoneNumber: user.phoneNumber,
        firstName: firstName || user.firstName,
        lastName: lastName || user.lastName,
        isVerified: user.isVerified
      });

      res.json({
        message: "Profile updated successfully",
        user: {
          id: updatedUser.id,
          phoneNumber: updatedUser.phoneNumber,
          firstName: updatedUser.firstName,
          lastName: updatedUser.lastName,
          isVerified: updatedUser.isVerified
        }
      });
    } catch (error) {
      console.error("Update profile error:", error);
      res.status(500).json({ message: "Failed to update profile" });
    }
  }
};

client/src/components/ask-ai.tsx.content:
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Brain, Send, Loader2, MessageSquare, X, AlertTriangle, Database, FileText, FolderOpen } from "@/lib/icons";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

interface AskAIProps {
  isHighlighted?: boolean;
}

interface AIResponse {
  analysis: string;
  sources: string[];
  databaseResults: number;
  driveResults: number;
  enhanced: boolean;
}

export default function AskAI({ isHighlighted = false }: AskAIProps) {
  const [query, setQuery] = useState("");
  const [analysis, setAnalysis] = useState("");
  const [sources, setSources] = useState<string[]>([]);
  const [dataStats, setDataStats] = useState({ database: 0, drive: 0 });
  const [showDiscussion, setShowDiscussion] = useState(false);
  const { toast } = useToast();

  const queryMutation = useMutation({
    mutationFn: async (stockQuery: string) => {
      // Show analysis progress notification
      toast({
        title: "AI Analyzing...",
        description: "Reading quarterly results → investor presentation → call transcript (this may take up to 2 minutes)",
        duration: 15000,
      });

      const response = await apiRequest("POST", "/api/stock-ai/query", { query: stockQuery });
      const data: AIResponse = await response.json();
      return data;
    },
    onSuccess: (data) => {
      setAnalysis(data.analysis);
      setSources(data.sources || []);
      setDataStats({ database: data.databaseResults || 0, drive: data.driveResults || 0 });
      setShowDiscussion(true);

      const sourceCount = data.sources?.length || 0;
      toast({
        title: "Analysis Complete",
        description: `Found ${sourceCount} data sources from your files`,
      });
    },
    onError: (error) => {
      const errorMessage = error instanceof Error ? error.message : "Failed to analyze stock";
      console.error("AI Query Error:", error);

      let userMessage = errorMessage;
      if (errorMessage.includes('timeout') || errorMessage.includes('Request timeout')) {
        userMessage = "Analysis taking longer than expected. Large documents are being processed. Please try again.";
      } else if (errorMessage.includes('500')) {
        userMessage = "Server error during analysis. Please try again in a moment.";
      } else if (errorMessage.includes('408')) {
        userMessage = "Request timeout. The AI is processing large documents. Please wait and try again.";
      }

      toast({
        title: "Analysis Failed",
        description: userMessage,
        variant: "destructive",
        duration: 8000,
      });
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    queryMutation.mutate(query);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  return (
    <>
      {/* Thinking notification with moving dots - positioned above highlighted input */}
      {queryMutation.isPending && isHighlighted && (
        <div className="mb-1 flex justify-center">
          <div className="bg-blue-500 text-white text-xs px-3 py-1 rounded-full flex items-center gap-1">
            <span>Thinking</span>
            <div className="flex gap-0.5">
              <div className="w-1 h-1 bg-white rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
              <div className="w-1 h-1 bg-white rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
              <div className="w-1 h-1 bg-white rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
            </div>
          </div>
        </div>
      )}

      {/* Ultra Compact Ask AI Input */}
      <div className={`mb-2 ${isHighlighted ? 'ring-1 ring-blue-400 ring-opacity-20 rounded' : ''}`}>
        <div className={`p-2 rounded ${isHighlighted ? 'bg-blue-50 dark:bg-blue-950 border border-blue-200 dark:border-blue-800' : 'bg-gray-50 dark:bg-gray-800'}`}>
          <form onSubmit={handleSubmit}>
            <div className="flex items-center gap-2">
              <Brain className="h-3 w-3 text-blue-500 flex-shrink-0" />
              <Input
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder="Ask AI about any stock..."
                className="flex-1 h-7 text-xs border-0 bg-white dark:bg-gray-700 px-2"
                disabled={queryMutation.isPending}
              />
              <Button 
                type="submit" 
                size="sm"
                disabled={queryMutation.isPending || !query.trim()}
                className="bg-blue-500 hover:bg-blue-600 text-white h-7 px-2"
              >
                {queryMutation.isPending ? (
                  <Loader2 className="h-3 w-3 animate-spin" />
                ) : (
                  <Send className="h-3 w-3" />
                )}
              </Button>
              {isHighlighted && (
                <span className="px-1 py-0.5 bg-blue-500 text-white text-xs rounded-full">
                  NEW
                </span>
              )}
            </div>
          </form>
        </div>
      </div>

      {/* Separate Stock Discussion Section */}
      {showDiscussion && analysis && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-900 rounded-lg max-w-2xl w-full max-h-[80vh] overflow-hidden">
            <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-gray-700">
              <div className="flex items-center gap-2">
                <MessageSquare className="h-5 w-5 text-blue-500" />
                <h2 className="text-lg font-semibold text-gray-900 dark:text-gray-100">
                  Stock Discussion
                </h2>
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setShowDiscussion(false)}
                className="h-8 w-8 p-0"
              >
                <X className="h-4 w-4" />
              </Button>
            </div>

            <div className="p-4 overflow-y-auto max-h-[60vh]">
              <div className="mb-4 p-3 bg-blue-50 dark:bg-blue-950 rounded-lg border-l-4 border-blue-500">
                <div className="flex items-center gap-2 mb-2">
                  <Brain className="h-4 w-4 text-blue-500" />
                  <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
                    Your Query: "{query}"
                  </span>
                </div>
              </div>

              {/* Data Sources Information */}
              {(sources.length > 0 || dataStats.database > 0 || dataStats.drive > 0) && (
                <div className="mb-4 p-3 bg-green-50 dark:bg-green-950 rounded-lg border border-green-200 dark:border-green-800">
                  <div className="flex items-center gap-2 mb-2">
                    <Database className="h-4 w-4 text-green-600" />
                    <span className="text-sm font-medium text-green-800 dark:text-green-300">
                      Enhanced AI with Your Data
                    </span>
                  </div>
                  <div className="grid grid-cols-2 gap-4 text-xs text-green-700 dark:text-green-300">
                    <div className="flex items-center gap-1">
                      <FileText className="h-3 w-3" />
                      <span>Database: {dataStats.database} articles</span>
                    </div>
                    <div className="flex items-center gap-1">
                      <FolderOpen className="h-3 w-3" />
                      <span>Google Drive: {dataStats.drive} files</span>
                    </div>
                  </div>
                  {sources.length > 0 && (
                    <div className="mt-2 text-xs text-green-600 dark:text-green-400">
                      Sources: {sources.join(', ')}
                    </div>
                  )}
                </div>
              )}

              {/* SEBI Compliance Warning */}
              <div className="mb-6 p-5 bg-gradient-to-r from-red-50 to-orange-50 dark:from-red-900/20 dark:to-orange-900/20 border-l-4 border-red-500 rounded-r-xl shadow-sm">
                <div className="flex items-start space-x-3">
                  <div className="p-2 bg-red-500 rounded-lg">
                    <AlertTriangle className="h-5 w-5 text-white" />
                  </div>
                  <div>
                    <h4 className="font-bold text-red-800 dark:text-red-300 text-lg mb-3">
                      ⚠️ SEBI Regulatory Disclaimer
                    </h4>
                    <div className="text-red-700 dark:text-red-300 space-y-2 text-sm leading-relaxed">
                      <p className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 bg-red-500 rounded-full"></span>
                        This is educational content only, NOT investment advice
                      </p>
                      <p className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 bg-red-500 rounded-full"></span>
                        Provider is not a SEBI-registered investment advisor
                      </p>
                      <p className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 bg-red-500 rounded-full"></span>
                        Consult SEBI-registered advisor before making investment decisions
                      </p>
                      <p className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 bg-red-500 rounded-full"></span>
                        Past performance does not guarantee future results
                      </p>
                      <p className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 bg-red-500 rounded-full"></span>
                        Stock investments are subject to market risks
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
                <div className="p-4 border-b border-gray-100 dark:border-gray-800 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 rounded-t-xl">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-blue-500 rounded-lg">
                      <Brain className="h-5 w-5 text-white" />
                    </div>
                    <div>
                      <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100">
                        Educational Stock Analysis
                      </h3>
                      <p className="text-sm text-gray-600 dark:text-gray-400">
                        Powered by Perplexity AI • Beta Testing
                      </p>
                    </div>
                  </div>
                </div>

                <div className="p-6">
                  <div className="prose prose-gray dark:prose-invert max-w-none">
                    <div className="text-gray-800 dark:text-gray-200 leading-relaxed text-base">
                      {/* Enhanced markdown and table rendering */}
                      <div className="markdown-content">
                        {(() => {
                          let processedContent = analysis;

                          // Handle main headers with ##
                          processedContent = processedContent.replace(/^## (.*$)/gm, '<h2 class="text-2xl font-bold mb-6 mt-8 text-blue-600 dark:text-blue-400 border-b-2 border-blue-200 dark:border-blue-800 pb-2">$1</h2>');

                          // Handle sub-headers with ###
                          processedContent = processedContent.replace(/^### (.*$)/gm, '<h3 class="text-lg font-semibold mb-4 mt-6 text-gray-800 dark:text-gray-200 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 p-3 rounded-lg border-l-4 border-blue-500">$1</h3>');

                          // Handle bold text and financial terms
                          processedContent = processedContent.replace(/\*\*(.*?)\*\*/g, '<strong class="font-semibold text-blue-700 dark:text-blue-300">$1</strong>');

                          // Process complete markdown tables
                          const completeTablePattern = /(\|.*\|(?:\n|\r\n?)?)+/g;
                          const tableMatches = processedContent.match(completeTablePattern);

                          if (tableMatches) {
                            tableMatches.forEach(tableBlock => {
                              const lines = tableBlock.trim().split(/\n|\r\n?/).filter(line => line.includes('|'));

                              if (lines.length >= 3) { // Header + separator + at least one data row
                                const headerLine = lines[0];
                                const separatorLine = lines[1];
                                const dataLines = lines.slice(2);

                                // Check if this is a proper table (has separator line with dashes)
                                if (separatorLine.includes('---') || separatorLine.includes('-')) {
                                  const headerCells = headerLine.split('|')
                                    .filter(cell => cell.trim())
                                    .map(cell => cell.trim().replace(/^\*\*|\*\*$/g, ''));

                                  let tableHTML = '<div class="my-6"><table class="w-full border-collapse bg-white dark:bg-gray-800 rounded-lg overflow-hidden shadow-lg border border-gray-200 dark:border-gray-700">';

                                  // Table header
                                  tableHTML += '<thead><tr>';
                                  headerCells.forEach(cell => {
                                    tableHTML += `<th class="bg-gradient-to-r from-blue-600 to-blue-700 text-white font-semibold text-left px-4 py-3 border-b-2 border-blue-800">${cell}</th>`;
                                  });
                                  tableHTML += '</tr></thead>';

                                  // Table body
                                  tableHTML += '<tbody>';
                                  dataLines.forEach((line, index) => {
                                    const cells = line.split('|')
                                      .filter(cell => cell.trim())
                                      .map(cell => cell.trim());

                                    if (cells.length === headerCells.length) {
                                      tableHTML += `<tr class="${index % 2 === 0 ? 'bg-gray-50 dark:bg-gray-900' : 'bg-white dark:bg-gray-800'} hover:bg-blue-50 dark:hover:bg-gray-700 transition-colors">`;
                                      cells.forEach(cell => {
                                        tableHTML += `<td class="px-4 py-3 border-b border-gray-200 dark:border-gray-600 text-gray-800 dark:text-gray-200 leading-relaxed">${cell}</td>`;
                                      });
                                      tableHTML += '</tr>';
                                    }
                                  });
                                  tableHTML += '</tbody></table></div>';

                                  processedContent = processedContent.replace(tableBlock, tableHTML);
                                }
                              }
                            });
                          }

                          // Handle numbered lists and bullet points
                          processedContent = processedContent.replace(/^\d+\.\s+(.+)$/gm, '<div class="flex items-start mb-2"><span class="inline-flex items-center justify-center w-6 h-6 text-xs font-medium text-white bg-blue-500 rounded-full mr-3 mt-0.5 flex-shrink-0">•</span><span class="text-gray-700 dark:text-gray-300">$1</span></div>');

                          // Handle bullet points
                          processedContent = processedContent.replace(/^-\s+(.+)$/gm, '<div class="flex items-start mb-2"><span class="inline-flex items-center justify-center w-2 h-2 bg-blue-400 rounded-full mr-3 mt-2 flex-shrink-0"></span><span class="text-gray-700 dark:text-gray-300">$1</span></div>');

                          // Handle financial figures and percentages with highlighting
                          processedContent = processedContent.replace(/₹[\d,]+(?:\.\d+)?(?:\s*(?:cr|crore|lakh|thousand|billion|million))?/gi, '<span class="font-semibold text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/20 px-1 py-0.5 rounded">$&</span>');
                          processedContent = processedContent.replace(/\d+(?:\.\d+)?%/g, '<span class="font-semibold text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 px-1 py-0.5 rounded">$&</span>');

                          // Handle line breaks but preserve formatting
                          processedContent = processedContent.replace(/\n\n/g, '<div class="mb-4"></div>');
                          processedContent = processedContent.replace(/\n/g, '<br/>');

                          return <div dangerouslySetInnerHTML={{ __html: processedContent }} />;
                        })()}
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-4 p-3 bg-yellow-50 dark:bg-yellow-950 rounded-lg border-l-4 border-yellow-500">
                <div className="flex items-center gap-2 mb-2">
                  <MessageSquare className="h-4 w-4 text-yellow-600" />
                  <span className="text-sm font-medium text-yellow-800 dark:text-yellow-200">
                    Stock-Specific Discussion
                  </span>
                </div>
                <p className="text-sm text-yellow-700 dark:text-yellow-300">
                  This dedicated section focuses only on stock-specific queries and analysis. 
                  Ask follow-up questions about fundamentals, technicals, or investment strategy.
                </p>
              </div>
            </div>

            <div className="p-4 border-t border-gray-200 dark:border-gray-700">
              <Button
                onClick={() => setShowDiscussion(false)}
                className="w-full bg-blue-500 hover:bg-blue-600 text-white"
              >
                Close Discussion
              </Button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

